window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q07"]=window.__LIBQ["tien-nghich"]["q07"]||{};window.__LIBQ["tien-nghich"]["q07"]["artifacts"]={"updatedAt":"2026-07-06","count":144,"artifacts":[{"id":"oan-anh","name":"Oán ảnh","cn":"","aliases":["Lệ nhi"],"category":"phap-bao","categoryLabel":"Pháp bảo đặc thù","phamCap":"không rõ","soHuu":["Liễu Mi"],"trangThai":"đang tồn tại","blurb":"Đứa nhỏ của Vương Lâm và Liễu Mi bị luyện hóa trăm năm thành oán ảnh. Liễu Mi dùng nó như pháp bảo đặc thù để trả thù và khống chế tâm thần Vương Lâm.","detail":"Oán ảnh vốn là đứa nhỏ có quan hệ huyết mạch với Vương Lâm. Liễu Mi luyện hóa nó trăm năm, gieo vào ý thức nó rằng phụ thân đã vứt bỏ nó, rồi đưa ra trước mặt Vương Lâm như một đòn trả thù trực diện vào tâm thần. Khi Liễu Mi gọi Lệ nhi, âm thanh từ oán ảnh trong sương đen khiến Vương Lâm đau đớn như bị xé nát tâm can.","nguon":["@c0635"]},{"id":"tien-ve-khoi-loi","name":"Tiên vệ khôi lỗi","cn":"","aliases":["Tiên vệ"],"category":"phap-bao","categoryLabel":"Khôi lỗi","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang do Vương Lâm điều khiển","blurb":"Khôi lỗi Tiên vệ được Vương Lâm gọi về khi nhận ra oán ảnh trong sương đen. Nó hóa thành bóng ma lớn bao phủ màn sương để ngăn oán ảnh hành động.","detail":"Ngay sau khi cảm nhận quan hệ huyết mạch với oán ảnh, Vương Lâm thu chiêu và gọi Tiên vệ khôi lỗi. Khôi lỗi bao phủ màn sương đen, tạo lớp khống chế để ngăn oán ảnh tiếp tục hành động trong lúc Vương Lâm đối diện Liễu Mi.","nguon":["@c0635"]},{"id":"co-kinh","name":"Cổ kính","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Tiên bảo","phamCap":"Hạ phẩm Tiên bảo","soHuu":["Liễu Mi"],"trangThai":"đang do Liễu Mi sử dụng","blurb":"Hạ phẩm Tiên bảo do Huyễn gia Lão Tổ tặng Liễu Mi. Nàng lấy cổ kính ra để chắn Hoàng tuyền chỉ của Vương Lâm.","detail":"Trong lúc bị Vương Lâm dùng Hoàng tuyền chỉ công kích, Liễu Mi lùi lại và lấy Cổ kính ra phòng ngự. Pháp bảo này được xác nhận là Hạ phẩm Tiên bảo do Huyễn gia Lão Tổ tặng cho nàng.","nguon":["@c0635"]},{"id":"hac-cham-hon-thu-tu","name":"Hắc châm","cn":"","aliases":["Hồn thứ tư"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Liễu Mi"],"trangThai":"đang do Liễu Mi sử dụng","blurb":"Cây châm đen do Liễu Mi phóng ra bằng máu trong lúc nguy cấp. Nó ngăn Thất Tinh kiếm trận và xuyên qua Tịch Diệt chỉ phong trước khi bị Vương Lâm dùng Định khống chế.","detail":"Khi bị Thất Tinh kiếm trận và Tịch Diệt chỉ ép sát, Liễu Mi cắn lưỡi phun máu, từ máu tươi bay ra một cây châm màu đen. Hắc châm còn được gọi là Hồn thứ tư, có thể xoay quanh người nàng để chống kiếm khí và chỉ phong, nhưng bị Vương Lâm thi triển Định khiến khựng lại.","nguon":["@c0635"]},{"id":"thien-nghich-khong-gian","name":"Thiên nghịch không gian","cn":"","category":"phap-bao","categoryLabel":"Không gian pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang dùng","blurb":"Không gian trong Thiên nghịch, nơi Vương Lâm đưa oán anh Bình nhi đã bị phong ấn vào để tạm trấn giữ.","detail":"Sau khi dùng cấm chế thu nhỏ và phong ấn oán anh, Vương Lâm đưa Bình nhi vào Thiên nghịch không gian, đồng thời phân một cỗ nguyên thần vào đó để tiếp tục xua oán khí cho con về sau.","nguon":["@c0637"]},{"id":"de-tu-hon-cua-ton-hon-phien","name":"Đệ tử hồn của Tôn Hồn Phiên","cn":"","category":"khac","categoryLabel":"Hồn phách liên quan pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đã nhập lại Tôn Hồn Phiên","blurb":"Hồn phách thuộc Tôn Hồn Phiên được Vương Lâm chụp từ hư không và đưa trở lại trong phiên.","detail":"Vương Lâm chụp vào hư không lấy lại đệ tử hồn, nắm trong tay rồi ném vào Tôn Hồn Phiên, nói với Độn Thiên sư phụ rằng đệ tử hồn đã được thu hồi và uy lực của phiên sẽ tái hiện.","nguon":["@c0637"]},{"id":"tinh-la-ban","name":"Tinh La bàn","cn":"","category":"phap-bao","categoryLabel":"Phi hành pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang dùng","blurb":"Phi hành pháp bảo hóa thành ngân quang đưa Vương Lâm rời Nhiễm Vân Tinh, lao tới Thiên Huyễn Tinh.","detail":"Sau khi xuyên qua Tỏa Tinh đại trận, Vương Lâm dùng Tinh La bàn. Pháp bảo hóa thành một đạo ngân quang, mang hắn theo vị trí trong ngọc giản của Tôn Tích thẳng tới Thiên Huyễn Tinh.","nguon":["@c0637","@c0672"]},{"id":"ngoc-gian-cua-ton-tich","name":"Ngọc giản của Tôn Tích","cn":"","category":"khac","categoryLabel":"Vật phẩm ghi tin tức","phamCap":"Không rõ","soHuu":["Tôn Tích","Vương Lâm"],"trangThai":"đã giao cho Vương Lâm","blurb":"Ngọc giản ghi vị trí Thiên Huyễn Tinh mà Tôn Tích đưa cho Vương Lâm.","detail":"Vị trí Thiên Huyễn Tinh được ghi rõ trong ngọc giản của Tôn Tích. Vương Lâm dựa vào thông tin này, dùng Tinh La bàn lao tới Thiên Huyễn Tinh sau khi rời Nhiễm Vân Tinh.","nguon":["@c0637"]},{"id":"phi-kiem-cua-ton-tich","name":"Phi kiếm của Tôn Tích","cn":"","category":"phap-bao","categoryLabel":"Phi hành pháp bảo","phamCap":"Không rõ","soHuu":["Tôn Tích"],"trangThai":"đang dùng","blurb":"Phi kiếm dưới chân Tôn Tích khi hắn từ thành trì bay ra gặp Vương Lâm.","detail":"Kiếm quang dưới chân Tôn Tích không ổn định khi hắn bay ra khỏi thành, biểu hiện sự sợ hãi sau khi chứng kiến Liễu Mi độc ác và Huyễn gia Lão Tổ từng đích thân tới.","nguon":["@c0637"]},{"id":"tien-bao-truyen-thua-cua-huyen-gia","name":"Tiên bảo truyền thừa của Huyễn gia","cn":"","category":"phap-bao","categoryLabel":"Tiên bảo","phamCap":"Truyền thừa tiên nhân","soHuu":["Huyễn gia"],"trangThai":"đang được Huyễn gia nắm giữ","blurb":"Tiên bảo do tiên nhân Huyễn gia để lại. Đây là một trong các nguyên nhân giúp Huyễn gia giữ địa vị lớn trên Thiên Huyễn Tinh.","detail":"Tiên bảo truyền thừa của Huyễn gia được nhắc trong phần xác lập thế cục ba gia tộc. Chương chưa mô tả hình dáng hoặc công năng cụ thể, chỉ cho biết nó là chỗ dựa quan trọng của Huyễn gia cùng ngọc giản hộ tộc.","nguon":["@c0638"]},{"id":"ngoc-gian-ho-toc-huyen-gia","name":"Ngọc giản hộ tộc Huyễn gia","cn":"","category":"khac","categoryLabel":"Ngọc giản truyền thừa","phamCap":"Truyền thừa tiên nhân","soHuu":["Huyễn gia"],"trangThai":"đang được Huyễn gia nắm giữ","blurb":"Ngọc giản hộ tộc chứa một đạo thần thông do tiên nhân Huyễn gia lưu lại. Nó góp phần khiến Huyễn gia được các thế lực trên Thiên Huyễn Tinh kiêng kị.","detail":"Ngọc giản hộ tộc Huyễn gia là vật truyền thừa của tiên nhân Huyễn gia. Nội dung chính được nhắc là một đạo thần thông bên trong, chưa lộ cách thi triển trong chương này.","nguon":["@c0638"]},{"id":"tui-tru-vat-chua-tien-ngoc-cua-thien-quy-tu","name":"Túi trữ vật chứa Tiên ngọc của Thiên Quỳ Tử","cn":"","category":"khac","categoryLabel":"Túi trữ vật","phamCap":"Chứa Tiên ngọc","soHuu":["Thiên Quỳ Tử","Vương Lâm"],"trangThai":"đã giao cho Vương Lâm","blurb":"Túi trữ vật Thiên Quỳ Tử đưa cho Vương Lâm để bồi thường. Vật bên trong là Tiên ngọc, dùng để xoa dịu việc lão đã chặn đường và suýt đắc tội người mà lão tưởng thuộc Lôi Tiên Điện.","detail":"Sau khi Xạ Thần xa hóa Lôi Thú khiến Thiên Quỳ Tử tin Vương Lâm là người Lôi Tiên Điện, lão lập tức đổi thái độ, tuyên bố Thiên gia không tham dự việc Huyễn gia và đưa túi trữ vật chứa Tiên ngọc cho Vương Lâm.","nguon":["@c0638"]},{"id":"vu-kiem-tien","name":"Vũ Kiếm tiên","cn":"","category":"phap-bao","categoryLabel":"Tiên kiếm","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Vũ Kiếm tiên là cự kiếm trong tay Vương Lâm, do Chu Dật phân ly và truyền thừa. Vương Lâm dùng nó để thi triển Trảm La Quyết khi công kích Huyễn gia đại trận.","detail":"Khi Huyễn gia đại trận bị Lôi Thú và Tiên vệ ép tới cực hạn, Vương Lâm vỗ túi trữ vật lấy ra Vũ Kiếm tiên. Kiếm này được nhắc là pháp bảo do Chu Dật tiền bối phân ly, truyền thừa cho Vương Lâm, và được dùng làm vật dẫn cho Trảm La Quyết.","nguon":["@c0639"]},{"id":"phuc-trach-ngoc-gian","name":"Phúc Trạch ngọc giản","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Chí bảo / ngọc giản","phamCap":"Chí bảo Huyễn gia, chứa Tiên pháp","soHuu":["Huyễn gia","Huyễn Vô Tình"],"trangThai":"dang-co","blurb":"Chí bảo Huyễn gia do tổ tiên ở Lôi chi Tiên giới lưu lại. Khi Huyễn gia đại trận bị phá, Huyễn Vô Tình mời ngọc giản này ra để đối phó Vương Lâm.","detail":"Phúc Trạch ngọc giản từ trong Nhà Tổ Huyễn gia bay lên, tỏa lực lượng tường hòa và khiến không gian quanh Nhà Tổ như tách thành một thế giới riêng. Dưới pháp quyết của Huyễn Vô Tình, nó hóa thành bóng người phát ra tiên lực nồng đậm, áp chế linh lực trên khắp Thiên Huyễn Tinh và bước tới tấn công Vương Lâm.","nguon":["@c0640"]},{"id":"van-dinh-chi-tinh-cua-chu-dat","name":"Vấn Đỉnh chi tinh của Chu Dật","cn":"","aliases":[],"category":"khac","categoryLabel":"Căn nguyên nguyên khí","phamCap":"Liên quan Vấn Đỉnh","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Căn nguyên giúp nguyên khí của Vương Lâm nhiều hơn tu sĩ Vấn Đỉnh bình thường. Nó được nhắc khi chương giải thích cái giá thi triển Trảm La Quyết.","detail":"Trảm La Quyết cần nguyên khí thân thể và nguyên thần dung hợp chặt chẽ, gây hao tổn lớn cho người thi triển. Vấn Đỉnh chi tinh của Chu Dật khiến nguyên khí trong cơ thể Vương Lâm dồi dào hơn mức thông thường, nhờ đó giảm bớt rủi ro khi dùng kiếm thức này.","nguon":["@c0640"]},{"id":"di-bao-cua-to-tien-huyen-gia","name":"Di bảo của Tổ tiên Huyễn gia","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Tiên bảo mất tích","phamCap":"Tiên bảo","soHuu":["Huyễn gia","Huyễn Vô Tướng"],"trangThai":"mat-tich","blurb":"Tiên bảo do tổ tiên Huyễn gia để lại nhưng đã mất tích cùng Huyễn Vô Tướng nhiều ngàn năm trước. Việc di bảo không xuất hiện khiến Thiên Quỳ Tử và lão già Hứa gia đều chú ý.","detail":"Huyễn Vô Tình nghĩ tới việc di bảo tổ tiên đã mất tích cùng Huyễn Vô Tướng nên không thể dùng trong trận với Vương Lâm, đành mời Phúc Trạch ngọc giản. Thiên Quỳ Tử và lão già Hứa gia cũng nhận ra điểm bất thường khi Huyễn gia không sử dụng món Tiên bảo này.","nguon":["@c0640"]},{"id":"tien-nghich-khong-gian","name":"Tiên Nghịch không gian","cn":"","aliases":[],"category":"khac","categoryLabel":"Không gian đặc thù","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Không gian liên quan Vương Lâm, nơi có Oán Anh. Chương này Vương Lâm nhớ tới Oán Anh trong không gian ấy trước khi gọi con bài trong nguyên thần.","detail":"Khi đối diện bóng người do Phúc Trạch ngọc giản hóa thành, Vương Lâm nhớ tới Oán Anh trong Tiên Nghịch không gian với cảm giác đau lòng. Sau đó hắn gọi một tồn tại trong nguyên thần và hứa sau trận sẽ thả tự do.","nguon":["@c0640"]},{"id":"vu-cau-mau-trang-nga","name":"Vụ cầu màu trắng ngà","cn":"","category":"khac","categoryLabel":"Vật tạo bởi tiên lực","phamCap":"Không rõ","soHuu":["hư ảnh Tiên nhân"],"trangThai":"da-dung","blurb":"Vụ cầu do hư ảnh Tiên nhân ngưng tụ trong lòng bàn tay sau khi rút linh khí toàn Thiên Huyễn Tinh. Nó là kết quả trực tiếp của Hoá Tiên Thuật trong trận đối đầu Tán Ma.","detail":"Hư ảnh Tiên nhân chuyển linh lực toàn tinh cầu thành tiên lực rồi ngưng tụ thành vụ cầu màu trắng ngà. Sự xuất hiện của vật này khiến Thiên Huyễn Tinh rơi vào trạng thái không còn chút linh lực nào, buộc Tán Ma dùng thủ đoạn rút tinh hồn để đối lại.","nguon":["@c0641"]},{"id":"tien-son-phap-bao","name":"Tiên sơn pháp bảo","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Tiên bảo","soHuu":["Tham Lang"],"trangThai":"không rõ","blurb":"Pháp bảo Tham Lang từng dùng ở Yêu Linh chi địa để rút Sơn hồn.","detail":"Khi chứng kiến Tán Ma thi triển Trừu hồn trên Thiên Huyễn Tinh, Vương Lâm nhớ lại Tham Lang từng dùng Tiên sơn pháp bảo rút Sơn hồn. So sánh này làm nổi bật quy mô khủng khiếp của việc Tán Ma rút tinh hồn cả tu chân tinh.","nguon":["@c0642"]},{"id":"tui-tru-vat-cua-lieu-mi","name":"Túi trữ vật của Liễu Mi","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Liễu Mi","Vương Lâm"],"trangThai":"Vương Lâm nhận được @c0643","blurb":"Túi trữ vật Liễu Mi để lại trước khi bị cắn nuốt ý cảnh. Nàng dặn nếu Huyễn Vô Tình không giết được Vương Lâm thì phải giao túi này cho hắn.","detail":"Sau biến cố Huyễn gia, Vương Lâm nhận túi trữ vật này theo giao ước mà Liễu Mi đã đặt ra. Bên trong chỉ có một viên đan dược và một khối ngọc giản.","nguon":["@c0643"]},{"id":"vien-dan-duoc-trong-tui-tru-vat","name":"Viên đan dược trong túi trữ vật","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"trong túi trữ vật Liễu Mi @c0643","blurb":"Viên đan dược là một trong hai vật nằm trong túi trữ vật Liễu Mi để lại cho Vương Lâm.","detail":"Chương 643 chỉ nêu trong túi trữ vật của Liễu Mi có một viên đan dược và một khối ngọc giản, chưa nói rõ công dụng của viên đan dược này.","nguon":["@c0643"]},{"id":"ngoc-gian-trong-tui-tru-vat","name":"Ngọc giản trong túi trữ vật","cn":"","category":"khac","categoryLabel":"Ngọc giản","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"trong túi trữ vật Liễu Mi @c0643","blurb":"Khối ngọc giản là vật còn lại trong túi trữ vật Liễu Mi để lại. Nội dung của nó chưa được trình bày trong chương này.","detail":"Vương Lâm phát hiện túi trữ vật Liễu Mi để lại chỉ có một viên đan dược và một khối ngọc giản. Ngọc giản này gắn với di vật cuối cùng của Liễu Mi sau khi nàng tiêu tán.","nguon":["@c0643"]},{"id":"dan-duoc-do-lieu-mi-luu-lai","name":"Đan dược do Liễu Mi lưu lại","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"không rõ","soHuu":["Vương Bình","Vương Lâm"],"trangThai":"đang dùng","blurb":"Đan dược do Liễu Mi lưu lại được dùng để giúp Vương Bình tiêu trừ oán khí. Nó phải phối hợp với thần thông Lôi hệ của Vương Lâm để duy trì quá trình trị liệu lâu dài.","detail":"Sau khi Vương Bình được xác nhận vốn là Oán Anh, số đan dược do Liễu Mi lưu lại trở thành thuốc điều trị cho đứa trẻ. Vương Lâm cho Vương Bình uống hằng ngày, rồi dùng thần thông Lôi hệ khu trừ hắc khí trong thân thể; nếu thiếu quá trình này, thân thể Vương Bình vẫn có nguy cơ trở lại trạng thái cũ.","nguon":["@c0644"]},{"id":"tro-cot-ton-thai","name":"Tro cốt Tôn Thái","cn":"","aliases":[],"category":"khac","categoryLabel":"Di vật","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"được Vương Lâm cất giữ","blurb":"Di vật còn lại sau khi Tôn Thái qua đời, được Vương Lâm đặt trong túi trữ vật theo lời hứa. Nó đánh dấu sự kết thúc của thời gian Tôn Thái ở bên hai cha con Vương Lâm.","detail":"Sau khi Tôn Thái chết, thi thể lão hóa thành một vò tro cốt. Vương Lâm giữ vò tro cốt ấy trong túi trữ vật, thực hiện lời hứa giữa hai người trước đó.","nguon":["@c0646"]},{"id":"phi-kiem-mau-xanh","name":"Phi kiếm màu xanh","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Người đàn ông trung niên cưỡi phi kiếm màu xanh"],"trangThai":"đang sử dụng @c0647","blurb":"Phi kiếm màu xanh dưới chân người đàn ông trung niên bay qua Kỳ Liên phong sau cơn dông. Ánh hàn quang của nó khiến Vương Bình lần đầu chứng kiến cảnh tượng tu sĩ phi hành.","detail":"Phi kiếm màu xanh là pháp bảo phi hành của tu sĩ trung niên xuất hiện trên Kỳ Liên phong. Người này cưỡi kiếm bay qua cầu vồng, nhìn thấy phụ tử Vương Lâm rồi tán thưởng phàm nhân có thể leo tới đỉnh núi trước khi rời đi.","nguon":["@c0647"]},{"id":"ngoc-gian-dua-tin","name":"Ngọc giản đưa tin","cn":"","aliases":["ngọc giản truyền tin"],"category":"khac","categoryLabel":"Vật phẩm truyền tin","phamCap":"Không rõ","soHuu":["Lão nhân cẩm y"],"trangThai":"đã bị bóp nát","blurb":"Vật phẩm truyền tin được lão nhân cẩm y sử dụng sau khi bị Vương Lâm trọng thương. Việc bóp nát ngọc giản báo hiệu khả năng truyền tin hoặc cầu viện bên ngoài.","detail":"Tại Tĩnh Nhã Hiên, sau khi kim đan nứt, lão nhân cẩm y lấy đan dược trong túi trữ vật nuốt vào rồi lập tức bóp nát ngọc giản đưa tin. Hành động này xảy ra ngay sau khi lão bị ánh mắt của Vương Lâm trọng thương vì ra tay với Vương Bình.","nguon":["@c0648"]},{"id":"phu-bai-vuong-phu","name":"Phủ bài Vương Phủ","cn":"","category":"khac","categoryLabel":"Biển phủ","phamCap":"Phàm vật","soHuu":["Vương Lâm"],"trangThai":"đang dùng","blurb":"Tấm biển mới treo trước đại viện ở thành bắc Kỳ Thủy. Vương Lâm tự tay đề hai chữ Vương Phủ lên đó.","detail":"Sau khi vào đại viện tại Kỳ Thủy thành, Vương Lâm cho tháo phủ bài cũ và thay bằng tấm biển do chính hắn đề hai chữ Vương Phủ. Đại viện từ đó mang danh Vương Phủ, nơi hắn và Vương Bình đối thoại về ba mươi năm phú quý.","nguon":["@c0650"]},{"id":"dai-dinh-mau-den","name":"Đại đỉnh màu đen","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tham Lang"],"trangThai":"đang dùng","blurb":"Đại đỉnh màu đen là pháp bảo Tham Lang lấy ra khi cảm ứng được bảo vật trên tinh cầu quỷ dị ở La Thiên Bắc Vực.","detail":"Tham Lang nhận ra cảm giác bảo vật trên tinh cầu bị sương mù che phủ giống lần đoạt đại đỉnh năm xưa. Hắn lấy đại đỉnh màu đen từ túi trữ vật, để nó trôi nổi trước mặt rồi theo sau tiến vào màn sương quanh tinh cầu.","nguon":["@c0653"]},{"id":"xa-than-xa","name":"Xạ Thần Xa","cn":"","aliases":["Lôi Thú","Ngân Giác lôi thú","Lôi thú sừng bạc"],"category":"phap-bao","categoryLabel":"Tọa kỵ lôi thú","phamCap":"Không rõ","soHuu":["Lôi Đạo Tử"],"trangThai":"bị lão già mang đi","blurb":"Lôi thú làm tọa kỵ cho Lôi Đạo Tử khi hắn giáng xuống Nhiễm Vân tinh.","detail":"Lôi thú xuất hiện trên không trung cùng Lôi Đạo Tử, toàn thân có lôi quang và nằm kiêu ngạo trên hư không. Nó được nhắc có nguồn gốc thánh thú Lôi chi tiên giới thời xưa, nhưng huyết thống hiện tại không còn thuần.","nguon":["@c0655","@c0703"]},{"id":"loi-vong","name":"Lôi võng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lôi Đạo Tử"],"trangThai":"hong","blurb":"Võng lôi quang Lôi Đạo Tử dùng để vây khốn tiên vệ khôi lỗi trong trận chiến với Vương Lâm.","detail":"Lôi Đạo Tử lấy lôi võng từ túi trữ vật, hóa thành một chiếc võng lôi quang lớn với nhiều hoa văn phù chú, dùng để bao vây tiên vệ khôi lỗi. Khi thiết côn thu lôi không chịu nổi lôi lực của Vương Lâm và sụp đổ, lôi lực phát tiết khiến lôi võng tan rã, tiên vệ thoát ra.","nguon":["@c0656"]},{"id":"thiet-con-khac-phu","name":"Thiết côn khắc phù","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lôi Đạo Tử"],"trangThai":"hong","blurb":"Cây côn đen dài ba trượng dùng để thu lôi, có phù văn và dây đỏ sậm quấn quanh.","detail":"Trong lúc đối đầu lôi cầu của Vương Lâm, Lôi Đạo Tử lấy ra thiết côn khắc phù, cắm xuống đất và phối hợp pháp quyết thu lôi để dẫn lôi lực vào pháp bảo. Lôi cầu của Vương Lâm quá mạnh khiến thiết côn rạn nứt, nổ tung rồi sụp đổ trước mặt Lôi Đạo Tử.","nguon":["@c0656"]},{"id":"loi-thu-loi-tien-dien","name":"Lôi thú Lôi Tiên Điện","cn":"","category":"khac","categoryLabel":"Tiên thú / lôi thú","phamCap":"Không rõ","soHuu":["Lôi Đạo Tử","Lôi Tiên Điện"],"trangThai":"đang giao chiến","blurb":"Lôi thú do Lôi Đạo Tử triệu ra bằng Lôi chi tiên thú. Nó không có lôi giác, huyết thống không thuần nhưng vẫn lao vào tử đấu với Ngân Giác lôi thú.","detail":"Lôi thú Lôi Tiên Điện được ngưng tụ từ lôi quang trên không trung, hóa ra sau khi Lôi Đạo Tử thi triển Lôi chi tiên thú. Khi đối mặt Ngân Giác lôi thú của Vương Lâm, nó bị huyết thống áp chế nhưng vì tôn nghiêm linh hồn vẫn gầm lên lao vào chém giết.","nguon":["@c0657"]},{"id":"phi-kiem-mau-bac","name":"Phi kiếm màu bạc","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo / lôi kiếm","phamCap":"Không rõ","soHuu":["Lôi Đạo Tử"],"trangThai":"đang sử dụng","blurb":"Phi kiếm do điện quang của Lôi Đạo Tử ngưng hình. Nó được dùng để đánh về phía tiên vệ khôi lỗi trong trận với Vương Lâm.","detail":"Trong lúc sinh tham niệm muốn đoạt Ngân Giác lôi thú, Lôi Đạo Tử vung tay khiến điện quang hóa thành phi kiếm màu bạc, trực chỉ tiên vệ khôi lỗi. Đây là một phần thế công của hắn trước khi thi triển Lôi tiên kiếp.","nguon":["@c0657"]},{"id":"dai-kiem","name":"Đại kiếm","cn":"","category":"phap-bao","categoryLabel":"Vũ khí","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang sử dụng","blurb":"Thanh đại kiếm được Vương Lâm lấy ra ở cuối chương. Hắn dùng nó để chuẩn bị đối mặt nguyên lực thần thông của Lôi Đạo Tử.","detail":"Sau khi Lôi Đạo Tử uy hiếp dùng nguyên lực pháp thuật bước thứ hai, Vương Lâm lấy đại kiếm, mũi kiếm nghiêng xuống, không lùi bước. Khi đối phương chạm tới nỗi đau Vương Bình, hắn nâng kiếm trong sát ý đỏ mắt.","nguon":["@c0657"]},{"id":"hai-dao-kim-sac-kiem-khi-tao-thanh-vuong-binh","name":"Hai đạo kim sắc kiếm khí tạo thành Vương Bình","cn":"","category":"khac","categoryLabel":"Kiếm khí","phamCap":"không rõ","soHuu":["Vương Bình","Vương Lâm"],"trangThai":"tan-di","blurb":"Hai đạo kiếm khí là bản chất thân thể và lớp thủ hộ oan hồn của Vương Bình. Chúng duy trì sự tồn tại của hắn trong hơn bảy mươi năm phàm tục.","detail":"Chương xác nhận một đạo kim sắc kiếm khí hóa thành thân thể Vương Bình, một đạo khác thủ hộ oan hồn. Khi Vương Bình từ biệt cha và Thanh Nghi, thân thể hắn hóa về kiếm khí, chỉ còn dải sáng trắng mang tia oán khí cuối cùng.","nguon":["@c0659"]},{"id":"dan-duoc-cuu-vuong-binh-nam-xua","name":"Đan dược cứu Vương Bình năm xưa","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"không rõ","soHuu":["Vương Lâm","Vương Bình"],"trangThai":"da-dung","blurb":"Đan dược Vương Lâm từng cho Vương Bình ăn khi nhận đứa trẻ từ Liễu Mi. Do bản chất Vương Bình chỉ là hồn phách và kiếm khí, thân thể không thể hấp thu như người thường.","detail":"Trong hồi tưởng chân tướng, Vương Bình nhớ thời thơ ấu uống thuốc đắng, còn Vương Lâm từng dùng đan dược và lôi hệ thần thông để xử lý oán khí. Đan dược không thể giải quyết tận gốc vì thân thể Vương Bình vốn không phải thân xác sinh trưởng bình thường.","nguon":["@c0659"]},{"id":"bay-thanh-bao-kiem","name":"Bảy thanh bảo kiếm","cn":"","category":"phap-bao","categoryLabel":"Phi kiếm","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Bảy thanh phi kiếm Vương Lâm dùng để bố trí Thất Tinh kiếm trận.","detail":"Trong sát cục vây Lôi Đạo Tử, Vương Lâm phóng bảy thanh bảo kiếm ra, tạo thành Thất Tinh kiếm trận xoay quanh đối phương và liên tục công kích lôi mạc phòng ngự.","nguon":["@c0660"]},{"id":"hon-thu-tu","name":"Hồn thứ tư","cn":"","category":"khac","categoryLabel":"Chủ hồn","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Chủ hồn trở về Tôn Hồn Phiên, góp phần tăng mạnh uy lực hồn phiên.","detail":"Sau khi hồn thứ tư quay về, Tôn Hồn Phiên tuy chưa đủ mười ức hồn thường nhưng uy lực tăng mạnh vì có nhiều hồn phách đại thần thông, giúp ba chung cực chủ hồn hiện ra trong trận vây Lôi Đạo Tử.","nguon":["@c0660"]},{"id":"ngoc-gian-loi-quang","name":"Ngọc giản lôi quang","cn":"","category":"khac","categoryLabel":"Vật phẩm phòng ngự","phamCap":"","soHuu":["Lôi Đạo Tử"],"trangThai":"da-dung","blurb":"Vật phẩm Lôi Đạo Tử bóp nát để tạo lôi mạc bảo vệ thân thể.","detail":"Khi bị Thất Tinh kiếm trận và nhiều thế công vây ép, Lôi Đạo Tử bóp nát ngọc giản lôi quang. Vật này hóa thành màn lôi bao quanh hắn, tạm thời chống đỡ công kích.","nguon":["@c0660"]},{"id":"ba-chung-cuc-chu-hon","name":"Ba chung cực chủ hồn","cn":"","category":"khac","categoryLabel":"Hồn phách chiến lực","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang thuộc Vương Lâm","blurb":"Ba chủ hồn của Vương Lâm tham gia uy hiếp nguyên thần Lôi Đạo Tử trong động phủ.","detail":"Ba chung cực chủ hồn phát tiếng hô khóc trong động phủ, phối hợp tiên vệ khôi lỗi, lôi thú, Thất Tinh kiếm trận và cấm chế điện quang để bao vây, tạo áp lực khiến Lôi Đạo Tử khó phản kháng.","nguon":["@c0661"]},{"id":"khoang-thach-kim-loai","name":"Khoáng thạch kim loại","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đã luyện hóa","blurb":"Vật liệu kim loại trong lòng tinh cầu bỏ hoang, bị Hoàng Tuyền lực hút ra để luyện khôi lỗi.","detail":"Vương Lâm dùng Hoàng Tuyền lực bao phủ tinh cầu bỏ hoang, hút khoáng thạch kim loại từ lòng đất rồi để chúng hòa tan trong hoàng tuyền, làm nguyên liệu tạo dịch cầu màu vàng.","nguon":["@c0661"]},{"id":"dich-cau-mau-vang","name":"Dịch cầu màu vàng","cn":"","category":"nguyen-lieu","categoryLabel":"Vật liệu luyện khôi lỗi","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đã dùng một phần","blurb":"Ba dịch cầu luyện từ khoáng thạch kim loại, dùng để nâng cấp thân thể khôi lỗi Lôi Đạo Tử.","detail":"Sau khi luyện hóa khoáng thạch kim loại bằng Hoàng Tuyền lực, Vương Lâm thu được ba dịch cầu màu vàng to bằng nắm tay. Hắn đặt một dịch cầu vào mi tâm thân thể Lôi Đạo Tử, khiến thân thể khôi lỗi đạt tới ngân cấp.","nguon":["@c0661"]},{"id":"cai-dinh-lon-cua-tham-lang","name":"Cái đỉnh lớn của Tham Lang","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo hoặc vật phẩm","phamCap":"không rõ","soHuu":["Tham Lang"],"trangThai":"đang thuộc Tham Lang","blurb":"Cái đỉnh lớn xuất hiện cùng Tham Lang trong lần hắn cố thoát khỏi Vân Hà tinh.","detail":"Khi Tham Lang chật vật lao ra khỏi sương mù Vân Hà tinh, trước mặt hắn có một cái đỉnh lớn cùng lao ra. Công năng và lai lịch của vật này chưa được nói rõ trong chương.","nguon":["@c0661"]},{"id":"tien-ve-thu-hai","name":"Tiên vệ thứ hai","cn":"","category":"phap-bao","categoryLabel":"Khôi lỗi bán thành phẩm","phamCap":"Thân thể ngân cực đỉnh phong","soHuu":["Vương Lâm"],"trangThai":"bán thành phẩm","blurb":"Khôi lỗi được Vương Lâm tế luyện từ Lôi Đạo Tử phối hợp đầu lôi thú nhưng thất bại ở bước cuối. Thành phẩm chỉ còn thân thể ngân cực đỉnh phong, chưa thể chiến đấu tự nhiên.","detail":"Vương Lâm kịp chém đứt liên hệ nguyên thần Lôi Đạo Tử và giữ lại thân thể khôi lỗi. Với thần thức hiện tại, hắn chỉ khiến tiên vệ thứ hai làm vài động tác đơn giản nên chưa thích hợp đưa vào thực chiến.","nguon":["@c0662"]},{"id":"ngoc-gian-khac-loi-thu","name":"Ngọc giản khắc lôi thú","cn":"","category":"phap-bao","categoryLabel":"Ngọc giản","phamCap":"Di vật Lôi Tiên Điện","soHuu":["Vương Lâm"],"trangThai":"đang có","blurb":"Ngọc giản trong túi trữ vật Lôi Đạo Tử, mặt trước khắc lôi thú kim giác và mặt sau có ký hiệu lớn. Bên trong ghi Đỉnh Hóa Thiên Địa cùng Lôi Nguyên Thuật.","detail":"Ngọc giản có lôi quang ngăn thần thức, mang một tia thiên địa lôi uy. Vương Lâm phá được trở ngại này nhờ lôi uy Thái Cổ trong nguyên thần và thu được hai thần thông lôi hệ quan trọng.","nguon":["@c0662"]},{"id":"loi-kiem-khong-ban-the","name":"Lôi kiếm không bản thể","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo lôi hệ","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang có","blurb":"Thanh kiếm hoàn toàn do tia chớp tạo thành, không có bản thể vật chất. Đây là pháp bảo từng được Lôi Đạo Tử dùng để giằng co với tiên vệ.","detail":"Khi kiểm kê di vật Lôi Đạo Tử, Vương Lâm nhận ra lôi kiếm này là vật từng đối kháng song quyền tiên vệ. Sau khi quan sát, hắn cất nó vào túi trữ vật.","nguon":["@c0662"]},{"id":"khoang-thach-bac-chua-loi-dien-luc","name":"Khoáng thạch bạc chứa lôi điện lực","cn":"","category":"nguyen-lieu","categoryLabel":"Khoáng thạch","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang có","blurb":"Hòn đá bạc to bằng nắm tay, chứa lôi điện lực. Khi Vương Lâm chạm vào, lôi đình nhập thể và bị nguyên thần nuốt lấy, để lại một chút nguyên lực thiên địa.","detail":"Khoáng thạch khiến Vương Lâm hứng thú vì có thể liên quan đến việc sinh ra nguyên lực thiên địa qua lôi đình nhập thể. Hắn không hấp thu hết ngay mà tạm thời cất đi.","nguon":["@c0662"]},{"id":"tui-tru-vat-cua-loi-dao-tu","name":"Túi trữ vật của Lôi Đạo Tử","cn":"","category":"khac","categoryLabel":"Túi trữ vật","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang có","blurb":"Túi trữ vật của Lôi Đạo Tử mất lạc ấn thần thức sau khi nguyên thần chủ nhân tiêu tán. Vương Lâm mở túi và kiểm kê bốn vật đáng chú ý.","detail":"Trong túi có ngọc giản khắc lôi thú, lôi kiếm không bản thể, khoáng thạch bạc chứa lôi điện lực và tiên ngọc. Việc túi trở thành vô chủ giúp Vương Lâm thu được Lôi Nguyên Thuật cùng nhiều vật lôi hệ.","nguon":["@c0662"]},{"id":"hai-dao-kiem-khi-lang-thien-hau","name":"Hai đạo kiếm khí Lăng Thiên Hậu","cn":"","category":"phap-bao","categoryLabel":"Kiếm khí","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang có","blurb":"Hai đạo kiếm khí của Lăng Thiên Hậu được Vương Lâm giữ trong động phủ. Khi hắn chuẩn bị tu luyện, kiếm khí dung nhập vào tiên vệ khôi lỗi để hộ pháp.","detail":"Kiếm khí lơ lửng trong động phủ của Vương Lâm trên tinh cầu bỏ hoang. Chúng được dùng cùng tiên vệ khôi lỗi đứng trước động phủ, bảo vệ Vương Lâm trong lúc nghiên cứu di vật và chuẩn bị nâng tu vi.","nguon":["@c0662"]},{"id":"ngoc-gian-huyet-sac","name":"Ngọc giản huyết sắc","cn":"","category":"khac","categoryLabel":"Vật phẩm truyền tống","phamCap":"Không rõ","soHuu":["Tử Tâm"],"trangThai":"đã kích hoạt","blurb":"Ngọc giản huyết sắc là vật Huyết Tổ tặng Tử Tâm để bảo mạng. Nó có thể truyền tống một lần từ bất kỳ nơi nào về Huyết Tinh nhưng cần thời gian mở ra.","detail":"Khi tinh cầu hoang dã sụp đổ và sóng gợn lan tới, Tử Tâm lấy ngọc giản huyết sắc ra để chuẩn bị truyền tống về Huyết Tinh. Hai huyết nô tự bạo nguyên thần nhằm tranh thủ thời gian cho nàng kích hoạt vật này.","nguon":["@c0663"]},{"id":"thiet-kiem-ri-set","name":"Thiết kiếm rỉ sét","cn":"","category":"phap-bao","categoryLabel":"Vũ khí","phamCap":"Không rõ","soHuu":["Thác Sâm"],"trangThai":"đang ở bên Thác Sâm","blurb":"Thiết kiếm rỉ sét cắm bên cạnh Thác Sâm trên cột đá trong Huyết Hải. Thân kiếm loang lổ rỉ sét và có vết máu nâu khô.","detail":"Trong Cổ Thần Chi Địa, Thác Sâm ngồi trên cột đá lớn nhất giữa Huyết Hải, bên cạnh là một thanh thiết kiếm rỉ sét. Vật này xuất hiện cùng cảnh hắn khắc tên Vương Lâm và tuyên bố sắp thoát khốn.","nguon":["@c0663"]},{"id":"tui-tru-vat-vuong-lam-luu-lai-cho-chu-nhu","name":"Túi trữ vật Vương Lâm lưu lại cho Chu Như","cn":"","category":"khac","categoryLabel":"Vật phẩm phong ấn ký ức","phamCap":"Không rõ","soHuu":["Chu Như"],"trangThai":"đã mở","blurb":"Túi trữ vật cổ xưa do Vương Lâm lưu lại cho Chu Như nhiều năm trước. Bên trong không có tài vật, chỉ có bạch quang nhập vào mi tâm nàng để giải khai ký ức phong ấn.","detail":"Trên đỉnh Chu Tước Sơn, Chu Như mở túi trữ vật đã trải qua mấy trăm năm. Bạch quang từ trong túi bay vào mi tâm, khiến ký ức bị phong ấn trong đầu nàng chậm rãi cởi bỏ và làm nàng hiểu Vương Lâm không muốn mình đi tìm hắn.","nguon":["@c0663"]},{"id":"bach-quang-trong-tui-tru-vat","name":"Bạch quang trong túi trữ vật","cn":"","category":"khac","categoryLabel":"Phong ấn ký ức","phamCap":"Không rõ","soHuu":["Chu Như"],"trangThai":"đã dung nhập mi tâm Chu Như","blurb":"Bạch quang là thứ duy nhất trong túi trữ vật Vương Lâm để lại cho Chu Như. Nó nhập vào mi tâm nàng và giải khai ký ức bị phong ấn.","detail":"Khi Chu Như mở túi trữ vật trên đỉnh Chu Tước Sơn, bạch quang lập tức bay ra, tiến vào mi tâm nàng. Sau đó ký ức bị phong ấn trong đầu Chu Như chậm rãi được cởi bỏ, kéo theo đoạn ký ức liên quan tới Uyển nhi và Vương Lâm.","nguon":["@c0663"]},{"id":"thang-tien-qua","name":"Thăng Tiên quả","cn":"","category":"nguyen-lieu","categoryLabel":"Linh quả","phamCap":"không rõ","soHuu":["Huyễn Gia","Vương Lâm"],"trangThai":"Vương Lâm thu lấy từ Huyễn Gia","blurb":"Linh quả Vương Lâm cần với số lượng lớn trong chương này.","detail":"Vương Lâm tới Thiên Huyễn Tinh để ép Huyễn Gia giao toàn bộ Thăng Tiên quả đã sưu tầm. Số lượng ấy vẫn chưa đủ, khiến hắn nảy ý mượn danh Lôi Tiên Điện để chiếm đoạt thêm ở La Thiên Bắc Vực.","nguon":["@c0664"]},{"id":"co-than-khi","name":"Cổ Thần Khí","cn":"","category":"khac","categoryLabel":"Vật liên quan Cổ Thần","phamCap":"không rõ","soHuu":[],"trangThai":"chưa rõ","blurb":"Vật mà Vương Lâm cho rằng bản tôn cần để trưởng thành.","detail":"Vương Lâm nghĩ bản tôn đã tới tứ tinh nhưng thiếu Cổ Thần Khí, rồi liên hệ tới Vọng Nguyệt trên Vân Hà tinh vì Vọng Nguyệt là ký sinh thể của Cổ Thần, có thể còn sót lại loại vật này.","nguon":["@c0664"]},{"id":"than-dieu-dau-tinh","name":"Thần điêu đầu tinh","cn":"","category":"khac","categoryLabel":"Dị thú dò tìm","phamCap":"không rõ","soHuu":["Sứ giả Tu Chân Liên Minh"],"trangThai":"được nhắc lại","blurb":"Dị thú từng đi cùng sứ giả Tu Chân Liên Minh và nhạy với Cổ Thần Khí.","detail":"Vương Lâm nhớ tới con thần điêu đầu tinh mà sứ giả Tu Chân Liên Minh từng mang theo ở Thiên Vận Tinh. Nó được nhắc vì có khả năng cảm ứng Cổ Thần Khí.","nguon":["@c0664"]},{"id":"loi-tien-lenh-bai","name":"Lôi Tiên lệnh bài","aliases":["ngọc giản của Lôi Đạo Tử"],"category":"phap-bao","categoryLabel":"Tín vật","phamCap":"Sứ giả Lôi Tiên Điện","soHuu":["Vương Lâm","Lôi Đạo Tử"],"trangThai":"Vương Lâm đang giữ","blurb":"Tín vật của Lôi Đạo Tử được Vương Lâm dùng để chứng minh thân phận Sứ giả Lôi Tiên Điện trước Thiên gia.","detail":"Khi được lấy ra, vật này phát lôi quang và lôi uy, phù hợp ký ức của Thiên Quỳ Tử về lệnh bài sứ giả nên khiến hắn không còn nghi ngờ thân phận của Vương Lâm.","nguon":["@c0665"]},{"id":"thien-nghich-chau","name":"Thiên Nghịch Châu","aliases":["Hạt châu Thiên Nghịch","Thiên Nghịch","Hạt Châu Thiên Nghịch","Thiên Nghịch châu"],"category":"phap-bao","categoryLabel":"Hạt châu","phamCap":"trọng bảo","soHuu":["Vương Lâm"],"trangThai":"chưa nhận chủ hoàn toàn","blurb":"Pháp bảo trục của Vương Lâm, đang cần viên mãn thuộc tính kim loại.","detail":"Mục tiêu chuyến vào Vân Hà Tinh là hấp thu tính kim loại từ xương Vọng Nguyệt để giúp Thiên Nghịch Châu viên mãn và có khả năng nhận chủ.","nguon":["@c0666"]},{"id":"kim-viem-quang-mach","name":"Kim Viêm quáng mạch","aliases":["Kim Viêm thạch"],"category":"nguyen-lieu","categoryLabel":"Khoáng mạch","phamCap":"xương Vọng Nguyệt","soHuu":[],"trangThai":"nằm trong thân thể Vọng Nguyệt","blurb":"Khoáng mạch kim tính trong xương Vọng Nguyệt, mục tiêu Vương Lâm muốn hấp thu cho Thiên Nghịch Châu.","detail":"Vương Lâm tìm tới Kim Viêm quáng mạch nhưng tạm dừng hấp thu vì phát hiện tiên lực bất thường, nghi có tu sĩ khác còn ẩn trong thân thể Vọng Nguyệt.","nguon":["@c0666"]},{"id":"son-thach-cua-tham-lang","name":"Sơn thạch của Tham Lang","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo sơn thạch","phamCap":"chưa rõ","soHuu":["Tham Lang","Vương Lâm"],"trangThai":"Vương Lâm thu được một phần","blurb":"Khối sơn thạch cực lớn từng được Tham Lang dùng ở vùng đất Yêu Linh, nay mắc trong khe xương Vọng Nguyệt.","detail":"Sơn thạch đã bị Kim Viêm quáng mạch đồng hóa nên cực khó lấy nguyên vẹn; Vương Lâm dùng kiếm khí của Lăng Thiên Hậu cắt tránh phần dính với xương rồi thu phần tách được vào túi trữ vật.","nguon":["@c0667"]},{"id":"nguyet-hoa","name":"Nguyệt Hoa","cn":"","category":"nguyen-lieu","categoryLabel":"Trọng bảo trong cơ thể Vọng Nguyệt","phamCap":"cực độc","soHuu":["Vọng Nguyệt"],"trangThai":"nằm trong cơ thể Vọng Nguyệt","blurb":"Vật trong cơ thể Vọng Nguyệt, chứa kịch độc và lực lượng nguy hiểm.","detail":"Theo ký ức Cổ Thần Đồ Ti, Nguyệt Hoa có kịch độc mà chỉ máu Cổ Thần có thể giải; nếu bị uy hiếp hoặc lấy ra có thể khiến Vọng Nguyệt tự bạo, với con khổng lồ này phạm vi ảnh hưởng có thể rất rộng.","nguon":["@c0667"]},{"id":"cu-dinh","name":"Cự Đỉnh","aliases":["Đại đỉnh thần bí của Tham Lang","Cự Đỉnh của Tham Lang"],"category":"phap-bao","categoryLabel":"Đại đỉnh","phamCap":"thần bí","soHuu":["Tham Lang"],"trangThai":"bị xúc tu quấn","blurb":"Đại đỉnh thần bí giúp Tham Lang giữ mạng trong nơi bài tiết của Vọng Nguyệt gần trăm năm.","detail":"Pháp bảo này từng chống lại lực hút nơi bài tiết, nhưng về sau bị xúc tu quấn quanh và thần thông như bị hấp thu mất tác dụng, khiến Tham Lang không thể thoát.","nguon":["@c0668"]},{"id":"xuong-song-cua-vong-nguyet","name":"Xương sống của Vọng Nguyệt","cn":"","category":"nguyen-lieu","categoryLabel":"Vật liệu hung thú","phamCap":"thân thể Vọng Nguyệt","soHuu":["Vương Lâm"],"trangThai":"đang bị kéo khỏi Vọng Nguyệt","blurb":"Hai nửa xương sống khổng lồ của Vọng Nguyệt được Vương Lâm và Tiên Vệ rút khỏi lòng đất Vân Hà Tinh.","detail":"Mỗi nửa xương kéo dài vô số dặm, lớn như dãy núi và không thể thu vào túi trữ vật, khiến Vương Lâm phải kéo trực tiếp trong lúc Vọng Nguyệt thức tỉnh và xúc tu truy cản.","nguon":["@c0669"]},{"id":"tu-thu-kiem","name":"Tử Thử kiếm","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thành phần Thất Tinh Kiếm Trận","soHuu":["Vương Lâm"],"trangThai":"hong","blurb":"Một thanh kiếm trong Thất Tinh Kiếm Trận. Trong chương 670, nó được Vương Lâm ra lệnh tự bạo đầu tiên trong khe nứt của Vọng Nguyệt.","detail":"Tử Thử kiếm là kiếm thể thuộc Thất Tinh Kiếm Trận. Khi bị Vọng Nguyệt truy sát, Vương Lâm gọi kiếm trận trở về rồi cho Tử Thử kiếm tự bạo trước, tạo lực nổ bên trong cơ thể Vọng Nguyệt để đổi lấy một nhịp thoát thân.","nguon":["@c0670"]},{"id":"hoi-tru-kiem","name":"Hợi Trư kiếm","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thành phần Thất Tinh Kiếm Trận","soHuu":["Vương Lâm"],"trangThai":"hong","blurb":"Một thanh kiếm trong Thất Tinh Kiếm Trận. Nó cùng các kiếm còn lại tự bạo sau Tử Thử kiếm để tạo lực hủy diệt bên trong cơ thể Vọng Nguyệt.","detail":"Hợi Trư kiếm thuộc Thất Tinh Kiếm Trận. Sau khi Tử Thử kiếm tự bạo, Vương Lâm ra lệnh cho Hợi Trư kiếm cùng các kiếm còn lại và tà hồn đồng loạt tự bạo, khiến Vọng Nguyệt khựng lại trong khoảnh khắc.","nguon":["@c0670"]},{"id":"vi-duong-kiem","name":"Vị Dương kiếm","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thành phần Thất Tinh Kiếm Trận","soHuu":["Vương Lâm"],"trangThai":"hong","blurb":"Một thanh kiếm trong Thất Tinh Kiếm Trận. Nó được dùng trong lần tự bạo toàn bộ kiếm trận để cản Vọng Nguyệt.","detail":"Vị Dương kiếm là một trong sáu kiếm được Vương Lâm cho tự bạo sau Tử Thử kiếm. Lực tự bạo phối hợp với tà hồn không đủ làm Vọng Nguyệt bị thương nặng, nhưng đủ khiến nó chậm lại đúng lúc.","nguon":["@c0670"]},{"id":"than-hau-kiem","name":"Thân Hầu kiếm","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thành phần Thất Tinh Kiếm Trận","soHuu":["Vương Lâm"],"trangThai":"hong","blurb":"Một thanh kiếm trong Thất Tinh Kiếm Trận. Nó cùng các kiếm còn lại tự bạo trong khe nứt của Vọng Nguyệt.","detail":"Thân Hầu kiếm thuộc Thất Tinh Kiếm Trận. Trong lúc truy đuổi sinh tử, Vương Lâm hy sinh cả kiếm trận, để Thân Hầu kiếm cùng những kiếm còn lại nổ tung nhằm tranh thủ thời cơ thoát khỏi Vọng Nguyệt.","nguon":["@c0670"]},{"id":"suu-nguu-kiem","name":"Sửu Ngưu kiếm","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thành phần Thất Tinh Kiếm Trận","soHuu":["Vương Lâm"],"trangThai":"hong","blurb":"Một thanh kiếm trong Thất Tinh Kiếm Trận. Nó bị Vương Lâm cho tự bạo trong cuộc thoát khỏi Vọng Nguyệt.","detail":"Sửu Ngưu kiếm là kiếm thể thuộc Thất Tinh Kiếm Trận. Nó cùng Hợi Trư kiếm, Vị Dương kiếm, Thân Hầu kiếm, Dần Hổ kiếm và Mão Thỏ kiếm tự bạo sau Tử Thử kiếm, tạo một đợt chấn động trong cơ thể Vọng Nguyệt.","nguon":["@c0670"]},{"id":"dan-ho-kiem","name":"Dần Hổ kiếm","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thành phần Thất Tinh Kiếm Trận","soHuu":["Vương Lâm"],"trangThai":"hong","blurb":"Một thanh kiếm trong Thất Tinh Kiếm Trận. Nó là một phần của lần tự hủy kiếm trận để ngăn Vọng Nguyệt trong thoáng chốc.","detail":"Dần Hổ kiếm thuộc nhóm kiếm của Thất Tinh Kiếm Trận. Vương Lâm không còn cách khác nên ra lệnh cho nó cùng các kiếm còn lại tự bạo, lấy lực hủy diệt đổi lấy một khoảnh khắc để bỏ chạy.","nguon":["@c0670"]},{"id":"mao-tho-kiem","name":"Mão Thỏ kiếm","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thành phần Thất Tinh Kiếm Trận","soHuu":["Vương Lâm"],"trangThai":"hong","blurb":"Một thanh kiếm trong Thất Tinh Kiếm Trận. Nó cùng toàn bộ kiếm trận bị hy sinh trong lúc Vương Lâm thoát khỏi Vọng Nguyệt.","detail":"Mão Thỏ kiếm là một kiếm thể của Thất Tinh Kiếm Trận. Trong chương 670, nó cùng các kiếm khác và tà hồn tự bạo trong khe nứt, khiến Vọng Nguyệt chậm lại trong một nhịp ngắn.","nguon":["@c0670"]},{"id":"ta-hon-tren-that-tinh-kiem-tran","name":"Tà hồn trên Thất Tinh Kiếm Trận","cn":"","category":"khac","categoryLabel":"Hồn thể","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"hong","blurb":"Tà hồn bám trên Thất Tinh Kiếm Trận, cùng kiếm thể tự bạo trong cuộc đào thoát khỏi Vọng Nguyệt.","detail":"Khi Vương Lâm ra lệnh cho Thất Tinh Kiếm Trận tự bạo, các tà hồn trên kiếm trận cũng vỡ nát, hóa thành lực lượng hủy diệt phối hợp với kiếm thể đánh vào cơ thể Vọng Nguyệt để đổi lấy khoảnh khắc trì hoãn.","nguon":["@c0671"]},{"id":"khoi-loi-tien-ve","name":"Khôi lỗi Tiên Vệ","cn":"","aliases":["Tiên Vệ","Con rối tiên vệ"],"category":"phap-bao","categoryLabel":"Con rối","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"hư tổn","blurb":"Con rối của Vương Lâm, tham gia khiêng xương Vọng Nguyệt chạy khỏi Vân Hà Tinh.","detail":"Tiên Vệ cùng Vương Lâm khiêng nửa xương Vọng Nguyệt lao ra tinh không, triển khai tốc độ đến cực hạn. Khi Vọng Nguyệt gầm rống, kim quang trên người Tiên Vệ sụp đổ và linh tính trong mắt trở nên ảm đạm.","nguon":["@c0672"]},{"id":"tien-tuu","name":"Tiên tửu","cn":"","aliases":[],"category":"khac","categoryLabel":"Tiên vật","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đã dùng hết","blurb":"Rượu tiên còn lại hai giọt, được Vương Lâm dùng để bùng phát tiên lực.","detail":"Trong lúc bị đàn Vọng Nguyệt nhỏ truy sát, Vương Lâm uống hết hai giọt tiên tửu còn lại. Tiên lực trong cơ thể hắn bùng nổ, giúp thi triển Định Thân Thuật ở quy mô vượt mức bình thường.","nguon":["@c0672"]},{"id":"binh-phong-son-ha-do","name":"Bình phong Sơn Hà Đồ","cn":"","aliases":["Sơn Hà Đồ","bình phong có dấu ấn Sơn Hà Đồ"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tham Lang"],"trangThai":"bị phá vỡ","blurb":"Bình phong mang dấu ấn Sơn Hà Đồ được Tham Lang dùng để chống một chỉ Cổ Thần.","detail":"Khi xúc tu của Vọng Nguyệt đuổi tới, Tham Lang lấy ra bình phong có dấu ấn Sơn Hà Đồ, khiến tinh không như biến mất và khí thế sơn hà hiện ra. Bình phong bị một chỉ Cổ Thần ép nứt rồi phá vỡ, khiến Tham Lang trọng thương.","nguon":["@c0672"]},{"id":"ton-tien-de-quan","name":"Tôn Tiên Đế Quan","cn":"","aliases":["vương miện"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Tham Lang","Vương Lâm"],"trangThai":"Vương Lâm thu được @c0673","blurb":"Vương miện kim quang có năm hạt châu ngũ hành, do Tham Lang dùng để chống Cổ Thần Chỉ. Sau khi Tham Lang bị đánh bay, pháp bảo vẫn nguyên vẹn và bị Vương Lâm thu lấy.","detail":"Tôn Tiên Đế Quan là vương miện Tham Lang lấy ra trong lúc nguy cấp, trên đó có năm hạt châu kim, mộc, thủy, hỏa, thổ và chứa chín nghìn chín trăm chín mươi chín linh hồn đế vương phàm nhân để luyện thành. Nó giúp Tham Lang chịu một chỉ Cổ Thần, nhưng linh hồn bên trong tan hết; vương miện không nứt, rơi vào tinh không rồi bị Vương Lâm dùng thần thức thu lấy.","nguon":["@c0673"]},{"id":"nam-hat-chau-ngu-hanh","name":"Năm hạt châu kim mộc thủy hỏa thổ","cn":"","aliases":["năm hạt châu ngũ hành"],"category":"khac","categoryLabel":"Bộ phận pháp bảo","phamCap":"không rõ","soHuu":["Tôn Tiên Đế Quan"],"trangThai":"gắn trên Tôn Tiên Đế Quan @c0673","blurb":"Năm hạt châu lớn gắn trên Tôn Tiên Đế Quan. Khi Tham Lang đội vương miện, chúng phát ra năm vầng sáng ngũ hành.","detail":"Năm hạt châu đại diện kim, mộc, thủy, hỏa, thổ là bộ phận nổi bật trên Tôn Tiên Đế Quan, cùng kim quang của vương miện bao bọc Tham Lang khi hắn chống Cổ Thần Chỉ.","nguon":["@c0673"]},{"id":"lac-an-cua-thien-van-tu","name":"Lạc ấn của Thiên Vận Tử","cn":"","category":"khac","categoryLabel":"Ấn ký","phamCap":"","soHuu":["Tham Lang","Thiên Vận Tử"],"trangThai":"Còn tồn tại trong cơ thể Tham Lang","blurb":"Ấn ký do Thiên Vận Tử để lại trong cơ thể Tham Lang, là lạc ấn duy nhất còn sót lại sau biến cố một chỉ Cổ Thần.","detail":"Sau khi Tham Lang bị trọng thương và rơi xuống tinh cầu nguyên thủy ở La Thiên Bắc Vực, phần lớn lạc ấn cường giả trong cơ thể hắn đã bị một chỉ Cổ Thần phá tan. Đạo lạc ấn của Thiên Vận Tử là lạc ấn duy nhất còn tồn tại, tiếp tục là dấu vết khống chế gắn với Tham Lang trong giai đoạn hắn chìm xuống lòng đất để khôi phục.","nguon":["@c0674"]},{"id":"de-tu-hon","name":"Đệ Tứ Hồn","cn":"","category":"khac","categoryLabel":"Chủ hồn","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang tồn tại","blurb":"Một chủ hồn được Vương Lâm phái rời khỏi tinh cầu để cảnh giới từ xa. Nó mở rộng phạm vi thần thức phòng hộ trong lúc Thiên Nghịch hấp thu Kim Viên Quáng.","detail":"Vì Thiên Nghịch quá trọng yếu và từng xuất hiện tại La Thiên Tinh Vực, Vương Lâm không chỉ dùng Tôn Hồn Phiên hộ pháp gần người mà còn sai Đệ Tứ Hồn bay ra ngoài tinh cầu ẩn nấp, mượn đó mở rộng thần thức để đề phòng biến động.","nguon":["@c0675"]},{"id":"nui-da-tien-gioi","name":"Núi đá tiên giới","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo / vật liệu tiên giới","phamCap":"Không rõ","soHuu":["Vương Lâm","Tham Lang"],"trangThai":"bị hư hại","blurb":"Bảo vật của Tham Lang bị Vương Lâm đoạt, bên trong còn tiên khí dày đặc dù đã hư hại. Nó giúp Vương Lâm cảm ngộ thần thông rút hồn linh vật.","detail":"Thần thức Tham Lang trong núi đá đã tiêu tán, bản thể cũng bị tổn hại nên Sơn Hồn rút ra không ổn định. Dù vậy, tiên khí trong núi đá vẫn rất mạnh và mở ra cho Vương Lâm hướng cảm ngộ trước loại thần thông rút linh hồn của Đệ Nhị Bộ.","nguon":["@c0675"]},{"id":"son-ha-thien-dao-do","name":"Sơn Hà Thiên Đạo Đồ","aliases":["Thiên Đạo Đồ"],"cn":"","category":"phap-bao","categoryLabel":"Tiên bảo nguyên bản","phamCap":"Tiên giới thượng phẩm tiên bảo xếp thứ năm","soHuu":[],"trangThai":"không rõ","blurb":"Tiên bảo thượng phẩm xếp thứ năm trong mười tiên bảo thượng phẩm của Tiên giới. Bản bình phong trong tay Tham Lang chỉ là bản in lại không hoàn chỉnh.","detail":"Sơn Hà Thiên Đạo Đồ được giới thiệu qua nguồn gốc của bình phong Sơn Hà Đồ. Truyền thuyết nói chỗ lợi hại chân chính của nó nằm ở nét vẽ Sơn Hà bằng máu, thậm chí tên Thiên Đạo Đồ phát sinh từ truyền thuyết máu vẽ tranh là máu của Thiên Đạo.","nguon":["@c0675"]},{"id":"doa-hong-mau-lam-cua-hong-diep","name":"Đóa hồng màu lam của Hồng Điệp","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm","Hồng Điệp"],"trangThai":"đã dung nhập Vương Miện","blurb":"Bông hồng tỏa lam quang và hàn khí kiêu ngạo, có liên hệ với Hồng Điệp. Khi đặt lên Vương Miện, nó tan thành lam quang dung nhập vào pháp bảo.","detail":"Vương Lâm nhớ tới Hồng Điệp và Ngũ Hành Linh Thể giả khi nghiên cứu năm hạt châu ngũ hành trên Vương Miện. Hắn lấy đóa hồng lam ra thử, khiến năm hạt châu phát sáng; đóa hồng tiêu tán thành điểm sáng màu lam nhập vào Vương Miện, để lại linh khí cùng bóng người múa kiếm mơ hồ.","nguon":["@c0675"]},{"id":"kim-vien-quang","name":"Kim Viên Quáng","cn":"","category":"nguyen-lieu","categoryLabel":"Khoáng vật thuộc tính kim","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đã bị Thiên Nghịch hấp thu","blurb":"Khoáng vật thuộc tính kim nằm trong xương mặt trăng, tức xương Vọng Nguyệt. Nó bị Thiên Nghịch hấp thu suốt ba tháng để hoàn tất thuộc tính kim.","detail":"Khi Vương Lâm đặt Thiên Nghịch Châu lên dãy núi do xương mặt trăng hóa thành, Kim Viên Quáng bên trong hóa thành từng sợi tơ vàng bị hạt châu hấp thụ rất chậm. Sau ba tháng, khoáng vật này biến mất, giúp thuộc tính kim của Thiên Nghịch viên mãn.","nguon":["@c0675"]},{"id":"ao-giap-mau-den-cua-loi-thu","name":"Áo giáp màu đen của Lôi Thú","cn":"","aliases":[],"category":"khac","categoryLabel":"Giáp","phamCap":"không rõ","soHuu":["Người đàn ông tóc đen cưỡi Lôi Thú"],"trangThai":"đang xuất hiện","blurb":"Bộ giáp màu đen khoác trên Lôi Thú của người đàn ông tóc đen.","detail":"Lôi Thú mà người đàn ông tóc đen cưỡi được bao phủ bởi một lớp giáp đen, khiến hình dáng của nó càng thêm dữ tợn khi bay trong tinh không về phía tầng đá vụn Nam Vực La Thiên.","nguon":["@c0678"]},{"id":"canh-cua-thien-dia","name":"Cánh cửa Thiên Địa","cn":"","category":"khac","categoryLabel":"Dị tượng cửa thần bí","phamCap":"Không rõ","soHuu":[],"trangThai":"đã mở khe hở trong Lôi Trì","blurb":"Cánh cửa lớn xuất hiện giữa Lôi Trì sau khi Thiên Nghịch biến hóa. Khe hở của nó khiến tâm thần Vương Lâm bị hút vào không gian Thiên Nghịch.","detail":"Cánh cửa Thiên Địa hiện ra giữa tử quang phủ khắp Lôi Trì; khi khe cửa mở, thân thể Vương Lâm dừng ngoài khe hở còn tâm thần dung nhập vào không gian bên trong. Bên ngoài cửa còn có cánh tay khổng lồ ngưng hóa, nhưng bị lôi điện màu tím trấn áp, tạo cơ hội để Vương Lâm tiếp cận.","nguon":["@c0679"]},{"id":"canh-tay-khong-lo-ben-ngoai-canh-cua","name":"Cánh tay khổng lồ bên ngoài cánh cửa","cn":"","category":"khac","categoryLabel":"Dị tượng thực thể thần bí","phamCap":"Không rõ","soHuu":[],"trangThai":"bị lôi điện màu tím trấn áp","blurb":"Cánh tay lớn ngưng hóa bên ngoài cánh cửa Thiên Địa trong Lôi Trì. Lần này nó bị vô số lôi điện màu tím quấn quanh, khiến Vương Lâm có cơ hội mạo hiểm tiếp cận khe cửa.","detail":"Cánh tay khổng lồ xuất hiện cùng dị biến cánh cửa Thiên Địa, là uy hiếp khiến Vương Lâm phải giữ đường lui. Tuy nhiên lôi điện màu tím từ Lôi Trì lập tức lao tới tấn công và trấn áp cánh tay, làm tình thế khác hẳn lần nguy hiểm trước đó.","nguon":["@c0679"]},{"id":"dao-hon-cua-than-cong-ho","name":"Đạo Hồn của Thân Công Hổ","cn":"","category":"khac","categoryLabel":"Vật bảo chứng tu đạo","phamCap":"Ý cảnh và đạo niệm Dương Thật","soHuu":["Vương Lâm"],"trangThai":"đã dung nhập nguyên thần Vương Lâm","blurb":"Đạo Hồn của Thân Công Hổ là phần hồn chứa ý cảnh và đạo niệm được hắn tự rút ra để xin dựa vào Vương Lâm. Vương Lâm thu nó vào nguyên thần làm bảo chứng cho lời nương tựa ngàn năm.","detail":"Khi Vương Lâm từ chối nhận người theo, Thân Công Hổ bấm quyết rút một luồng sáng màu đen từ Thiên Linh cái, bên trong ẩn chứa ý cảnh và đạo niệm của hắn. Sau khi xác nhận hắn không hối hận, Vương Lâm thu Đạo Hồn, nuốt vào và dung nhập nguyên thần.","nguon":["@c0681"]},{"id":"loi-dinh","name":"Lôi Đỉnh","cn":"","category":"khac","categoryLabel":"Đạo cụ truyền tống","phamCap":"Liên quan Lôi Tiên Giới","soHuu":[],"trangThai":"được dùng để vào Lôi Tiên Giới khi mở ra","blurb":"Lôi Đỉnh là vật được Thân Công Hổ nhắc tới như điều kiện để tiến vào Lôi Tiên Giới khi giới này mở ra. Nó gắn với lần mở Lôi Tiên Giới sau mười năm tại La Thiên.","detail":"Theo Thân Công Hổ, khi Lôi Tiên Giới mở ra, tu sĩ có thể dựa vào Lôi Đỉnh để đi vào. Vật này trở thành thông tin then chốt khiến Vương Lâm chú ý tới chuyến vào Lôi Tiên Giới nhằm tìm cơ hội tu luyện bằng tiên ngọc.","nguon":["@c0681"]},{"id":"van-dinh-chi-tinh","name":"Vấn Đỉnh Chi Tinh","cn":"","category":"khac","categoryLabel":"Vật liên quan cảnh giới","phamCap":"Không rõ","soHuu":[],"trangThai":"chưa có trong tay Vương Lâm","blurb":"Vấn Đỉnh Chi Tinh được nhắc như yếu tố mà tu sĩ Vấn Đỉnh bình thường có, còn Vương Lâm thì chưa sở hữu sau khi mới đạt Vấn Đỉnh.","detail":"Trong chương này, việc Vương Lâm chưa có Vấn Đỉnh Chi Tinh được dùng để giải thích vì sao nguyên lực của hắn yếu hơn tu sĩ Vấn Đỉnh bình thường, đặc biệt sau trận với Lôi Đạo Tử khiến nguyên lực gần chạm ranh giới thấp nhất.","nguon":["@c0682"]},{"id":"kiem-go-mau-tim","name":"Kiếm gỗ màu tím","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Chiến Không Liệt"],"trangThai":"đang sử dụng","blurb":"Pháp bảo màu tím của Chiến Không Liệt, dùng để phi hành và phối hợp thi triển thần thông.","detail":"Kiếm gỗ màu tím mang tử quang và hàn khí sắc bén. Khi Chiến Không Liệt vận chuyển thần thông, kiếm khí từ pháp bảo này dung hợp với lôi quang màu tím, tạo nên uy thế có thiên địa nguyên khí.","nguon":["@c0684"]},{"id":"tui-tru-vat-cua-than-cong-ho","name":"Túi trữ vật của Thân Công Hổ","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Thân Công Hổ"],"trangThai":"đang sở hữu","blurb":"Túi trữ vật Thân Công Hổ dùng để lấy đan dược trước trận chiến.","detail":"Sau khi nhận khảo nghiệm từ Vương Lâm, Thân Công Hổ vỗ túi trữ vật lấy ra một lọ đan dược để chuẩn bị cho tình thế giao chiến với Chiến Không Liệt.","nguon":["@c0684"]},{"id":"lo-dan-duoc-cua-than-cong-ho","name":"Lọ đan dược của Thân Công Hổ","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Thân Công Hổ"],"trangThai":"đang sở hữu","blurb":"Lọ đan dược Thân Công Hổ lấy ra trước khi giao chiến với Chiến Không Liệt.","detail":"Được lấy từ túi trữ vật ngay sau khi Vương Lâm tuyên bố xem trận chiến là khảo nghiệm. Công dụng cụ thể chưa được nêu trong chương này.","nguon":["@c0684"]},{"id":"dan-duoc-phat-hong-quang-cua-loi-tien-dien","name":"Đan dược phát hồng quang của Lôi Tiên Điện","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Đan dược Lôi Tiên Điện","soHuu":["Thân Công Hổ"],"trangThai":"da-dung","blurb":"Đan dược do Thân Công Hổ sử dụng trước khi quyết chiến với Chiến Không Liệt. Thuốc giúp hắn áp chế thương thế và tạm đẩy khí tức lên trạng thái mạnh hơn.","detail":"Thân Công Hổ bóp nát dược bình rồi nuốt các viên đan phát hồng quang. Sau khi dùng đan, khí tức toàn thân hắn tăng vọt hung hãn, giúp hắn cưỡng ép giữ trạng thái đỉnh cao để thi triển Dẫn lôi thuật đấu với Chiến Không Liệt.","nguon":["@c0685"]},{"id":"thu-trieu-tap-cua-loi-tien-dien","name":"Thư triệu tập của Lôi Tiên Điện","cn":"","category":"khac","categoryLabel":"Tín lệnh","phamCap":"Tín lệnh Lôi Tiên Điện","soHuu":["Chiến Không Liệt"],"trangThai":"dang-co","blurb":"Thư triệu tập mà Chiến Không Liệt đã nhận từ Lôi Tiên Điện. Nó báo hiệu hắn sẽ trở thành sứ giả của Lôi Tiên Điện cùng Thân Công Hổ.","detail":"Trước khi rời khỏi Lôi Trì, Chiến Không Liệt nói mình đã nhận thư triệu tập của Lôi Tiên Điện, sau này sẽ cùng Thân Công Hổ làm sứ giả trong hệ thống Lôi Tiên Điện.","nguon":["@c0685"]},{"id":"kiem-go-cua-chien-khong-liet","name":"Kiếm gỗ của Chiến Không Liệt","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Chiến Không Liệt"],"trangThai":"đang sử dụng","blurb":"Pháp bảo kiếm gỗ của Chiến Không Liệt, được dùng trong lần giao thủ với Thân Công Hổ tại Lôi Trì. Khi thúc nguyên khí, kiếm lan tử quang và phóng kiếm khí mạnh.","detail":"Kiếm gỗ bay lên từ dưới chân Chiến Không Liệt, được hắn phun nguyên khí lên để kích phát tử quang và kiếm khí nồng đậm. Nó đối kháng với Dẫn lôi thuật của Thân Công Hổ trong một lần va chạm khiến lôi quang tiêu tán, kiếm gỗ lui lại và hai bên đều bị đẩy lùi.","nguon":["@c0686"]},{"id":"ngoc-gian-truyen-am-cua-than-cong-ho","name":"Ngọc giản truyền âm của Thân Công Hổ","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm","Thân Công Hổ"],"trangThai":"đã giao cho Vương Lâm","blurb":"Ngọc giản Thân Công Hổ để lại cho Vương Lâm trước khi rời Lôi Trì. Bên trong có tinh đồ toàn bộ La Thiên Tinh Vực và phần giới thiệu tỉ mỉ nhiều nơi.","detail":"Trước khi bị Vương Lâm đuổi đi, Thân Công Hổ để lại ngọc giản truyền âm. Vật này chứa tinh đồ La Thiên Tinh Vực, chỉ rõ nhiều khu vực và giúp Vương Lâm không lạc đường khi muốn tìm một nơi bí mật để tu luyện, chuẩn bị cho Lôi Tiên Giới.","nguon":["@c0686"]},{"id":"ngoc-gian-oan-khi","name":"Ngọc giản oán khí","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm chứa","phamCap":"không rõ","soHuu":["Trương Tân Hải","Vương Lâm"],"trangThai":"đã giao cho Vương Lâm","blurb":"Ngọc giản chứa oán khí phàm nhân toàn Thanh Linh Tinh do Trương Tân Hải thu gom.","detail":"Trương Tân Hải hoàn thành việc thu gom oán khí phàm nhân trên Thanh Linh Tinh và giao toàn bộ cho Vương Lâm bằng ngọc giản; số oán khí này được Vương Lâm hấp thu vào Hoàng Tuyền.","nguon":["@c0689"]},{"id":"dan-duoc-vuong-lam-ban-cho-truong-gia","name":"Đan dược Vương Lâm ban cho Trương gia","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"không rõ","soHuu":["Con trai Trương Tân Hải"],"trangThai":"đã ban","blurb":"Đan dược Vương Lâm giao cho Trương gia để hỗ trợ con trai Trương Tân Hải trùng kích Hóa Thần.","detail":"Vương Lâm ban đan dược cho con trai Trương Tân Hải, nói rằng nếu tư chất không đủ thì có thể nhờ linh khí trong đan dược tăng thêm chút cơ hội Hóa Thần.","nguon":["@c0689"]},{"id":"tien-dich","name":"Tiên dịch","cn":"","aliases":[],"category":"khac","categoryLabel":"Tài nguyên tu luyện","phamCap":"tiên lực","soHuu":["Vương Lâm"],"trangThai":"đã dùng","blurb":"Tiên dịch là tài nguyên Vương Lâm uống sau khi dùng hết tiên ngọc để thúc đẩy tu vi.","detail":"Sau một năm hấp thu tiên khí trong trận pháp tiên ngọc, khi toàn bộ tiên ngọc đã dùng hết, Vương Lâm lập tức uống tiên dịch để lượng tiên lực lớn tiếp tục đẩy tu vi tới Vấn Đỉnh viên mãn.","nguon":["@c0689"]},{"id":"tien-son","name":"Tiên Sơn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang dùng","blurb":"Hòn đá biến hóa thành ngọn Tiên Sơn lớn, chứa tiên lực nồng đậm và uy áp.","detail":"Vương Lâm lấy hòn đá trong túi trữ vật hóa thành Tiên Sơn, rút khí tức tang thương từ đó để thi triển Trừu Linh Chi Lai.","nguon":["@c0690"]},{"id":"ngoc-gian-chua-oan-khi","name":"Ngọc giản chứa oán khí","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang có","blurb":"Ngọc giản chứa oán khí được Vương Lâm mang theo khi rời Thanh Linh Tinh.","detail":"Vật này liên quan tới việc Tuyền Hồn trong Hoàng Tuyền của Vương Lâm có dấu hiệu ngưng kết thức tỉnh.","nguon":["@c0690"]},{"id":"ngoc-gian-cua-than-cong-ho","name":"Ngọc giản của Thân Công Hổ","cn":"","category":"khac","categoryLabel":"Ngọc giản tình báo","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang dùng","blurb":"Ngọc giản ghi thông tin về các tu chân tinh và lượng Lôi Đỉnh các gia tộc thường nhận.","detail":"Vương Lâm dùng nó để chọn Thánh Đàn Tinh, nơi có hai gia tộc thường nhận nhiều Lôi Đỉnh, làm mục tiêu chờ đoạt.","nguon":["@c0690"]},{"id":"son-hon-tan","name":"Sơn Hồn Tán","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang có","blurb":"Pháp bảo liên quan hồn phách Tiên Sơn.","detail":"Khi lão già Âm Hư thi triển Đệ Tam Nhãn, hồng quang làm hồn phách Tiên Sơn từ Sơn Hồn Tán tan rã một phần, sau đó Vương Lâm thu hồi về Tiên Sơn.","nguon":["@c0691"]},{"id":"ngoc-gian-ghi-ba-than-thong","name":"Ngọc giản ghi ba thần thông","cn":"","category":"khac","categoryLabel":"Ngọc giản","phamCap":"không rõ","soHuu":["Lão già Trương gia"],"trangThai":"đã giao dịch","blurb":"Ba ngọc giản Vương Lâm dùng để ghi Tịch Diệt Chỉ, Hóa Ma Chỉ và Sát Lục Tiên Quyết.","detail":"Được dùng làm vật trao đổi để lấy ngọc giản Đệ Tam Nhãn từ lão già Âm Hư.","nguon":["@c0691"]},{"id":"ngoc-gian-de-tam-nhan","name":"Ngọc giản Đệ Tam Nhãn","cn":"","category":"khac","categoryLabel":"Ngọc giản","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang có","blurb":"Ngọc giản ghi thần thông Đệ Tam Nhãn.","detail":"Lão già Âm Hư ghi thuật vào ngọc giản và cố ý để lại vài chỗ sai lầm gây họa ngầm; Vương Lâm nhờ từng quan sát Đệ Tam Nhãn nên nhìn ra manh mối và dự định tu chỉnh.","nguon":["@c0691"]},{"id":"tien-loi-thu-ba","name":"Tiên Lôi thứ ba","cn":"","category":"khac","categoryLabel":"Lôi đình","phamCap":"không rõ","soHuu":[],"trangThai":"đã giáng xuống","blurb":"Đạo Tiên Lôi mạnh hơn hai lần trước, ngưng thành cơn lốc sấm sét khổng lồ.","detail":"Đạo lôi này gom gần như toàn bộ mây sấm trên Thanh Linh Tinh, được nguyên thần Vương Lâm nuốt một nửa, còn phần còn lại bị Lôi Đỉnh hút vào khiến đỉnh nứt vỡ.","nguon":["@c0692"]},{"id":"luu-tinh-loi-dinh","name":"Lưu tinh lôi đình","cn":"","category":"khac","categoryLabel":"Lôi đình hiện tượng","phamCap":"không rõ","soHuu":[],"trangThai":"đã dẫn Vương Lâm vào Lôi Tiên Giới","blurb":"Luồng lôi đình dạng lưu tinh kéo Vương Lâm vào Lôi Tiên Giới.","detail":"Khi xông vào tia chớp đỏ sậm, lôi lực của nó tăng mạnh, khóa thân thể và nguyên thần Vương Lâm rồi nện hắn xuống đại lục phía đông, tạo hố sâu và khiến hắn trọng thương.","nguon":["@c0694"]},{"id":"tien-but-lap-lanh-kim-quang","name":"Tiên bút lấp lánh kim quang","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang dùng","blurb":"Cây tiên bút kim quang Vương Lâm lấy ra khi đi vào thông đạo dưới lòng đất.","detail":"Vương Lâm lấy tiên bút từ túi trữ vật, phối hợp tiên lực và khe yêu dị ở mi tâm để mở đường trong bùn đất bị giam cầm.","nguon":["@c0694"]},{"id":"tien-dan","name":"Tiên đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"tiên đan","soHuu":[],"trangThai":"không rõ","blurb":"Đan dược hiếm trong Lôi Tiên Giới, được xem là một trong những cơ duyên khiến tu sĩ muốn tiến vào nơi này. Mỗi lần giới mở ra, số người tìm được tiên đan rất ít.","detail":"Vương Lâm hồi tưởng thông tin về Lôi Tiên Giới và nhận ra tiên đan là một lợi ích lớn tại nơi này. Loại đan dược này không dễ gặp, phụ thuộc vận số của người tiến vào Lôi Tiên Giới.","nguon":["@c0695"]},{"id":"tien-bao","name":"Tiên bảo","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"tiên bảo","soHuu":[],"trangThai":"không rõ","blurb":"Bảo vật cấp tiên trong Lôi Tiên Giới, thuộc nhóm cơ duyên được tu sĩ La Thiên tinh vực săn tìm. Việc có thể tìm được hay không phụ thuộc vào vận số của từng người.","detail":"Tiên bảo được nêu cùng tiên đan, tiên thuật, thi thể tiên nhân, vũng nguyên lực và nguyên khí như một trong các nguyên nhân khiến vô số tu sĩ muốn tiến vào Lôi Tiên Giới. Chương chưa nêu món tiên bảo cụ thể nào được Vương Lâm thu được ở thời điểm này.","nguon":["@c0695"]},{"id":"thi-the-tien-nhan","name":"Thi thể tiên nhân","cn":"","category":"khac","categoryLabel":"Di hài","phamCap":"tiên nhân","soHuu":[],"trangThai":"được treo thưởng","blurb":"Dị vật cực giá trị trong Lôi Tiên Giới, gần đây có tin phát hiện tám thi thể tiên nhân được bảo tồn nguyên vẹn. Đầu mối chính xác hoặc bản thân thi thể có thể đổi lấy lợi ích lớn từ Lôi Tiên Điện.","detail":"Theo hiểu biết Vương Lâm tổng hợp, thi thể tiên nhân trong Lôi Tiên Giới là mục tiêu tranh đoạt quan trọng. Lôi Tiên Điện treo giá cao cho manh mối chính xác, thậm chí người có thiên tư tốt nhờ đó có thể được một trong mười đại trưởng lão nhận làm đệ tử.","nguon":["@c0695"]},{"id":"vung-nguyen-luc","name":"Vũng nguyên lực","cn":"","category":"nguyen-lieu","categoryLabel":"Tài nguyên tu luyện","phamCap":"thiên địa nguyên lực nồng đậm","soHuu":[],"trangThai":"không rõ","blurb":"Nơi tích tụ thiên địa nguyên lực cực nồng trong Lôi Tiên Giới. Từng có tu sĩ Vấn Đỉnh kỳ nhờ tu luyện trong vũng nguyên lực mà đột phá khỏi bước đầu tiên tu đạo.","detail":"Vũng nguyên lực là một trong các cơ duyên khiến tu sĩ điên cuồng muốn vào Lôi Tiên Giới. Tin tức về người từ Vấn Đỉnh kỳ vượt qua bước đầu tiên nhờ vũng nguyên lực khiến tài nguyên này trở thành mục tiêu lớn đối với tu sĩ cấp cao.","nguon":["@c0695"]},{"id":"nguyen-khi","name":"Nguyên khí","cn":"","category":"khac","categoryLabel":"Pháp khí/tài nguyên đặc thù","phamCap":"không rõ","soHuu":[],"trangThai":"không rõ","blurb":"Pháp khí hoặc tài nguyên đặc thù trong Lôi Tiên Giới, chứa lực lượng kỳ dị khác tiên lực trong tiên ngọc. Người hấp thu ở cảnh giới khác nhau sẽ chuyển hóa thành tiên lực hoặc nguyên lực.","detail":"Nguyên khí được Vương Lâm nhắc như một lợi ích quan trọng của Lôi Tiên Giới. Nếu tu sĩ bước đầu tiên hấp thu thì sinh tiên lực; nếu tu sĩ bước thứ hai hấp thu thì chuyển thành nguyên lực, vì vậy nó có giá trị lớn với cả hai tầng tu sĩ.","nguon":["@c0695"]},{"id":"manh-vo-mau-xam-trang-co-tien-luc","name":"Mảnh vỡ màu xám trắng có tiên lực","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Vật phẩm","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm thu vào túi trữ vật","blurb":"Mảnh vỡ màu xám trắng có tiên lực là vật to bằng nắm tay, không trọn vẹn, giống một phần của cái bình. Nó phát ra dao động tiên lực và trở thành mục tiêu tranh đoạt của Hứa Phong Hàn.","detail":"Sau khi các sợi tơ nguyên lực trên mặt đất tan nát, Vương Lâm phát hiện vật màu xám trắng nằm trong bùn đất, phát ra dao động tiên lực. Hắn nhận ra vật này giống mảnh vỡ của một cái bình và thu vào túi trữ vật; ngay sau đó Hứa Phong Hàn xuất hiện, uy hiếp hắn giao vật rồi giao chiến.","nguon":["@c0696"]},{"id":"da-nui-cua-tien-gioi","name":"Đá núi của tiên giới","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Vật phẩm","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm đang giữ","blurb":"Đá núi của tiên giới là vật Vương Lâm lấy từ túi trữ vật trong lúc giao chiến. Hắn khiến nó hóa lớn thành tảng đá khổng lồ rồi rút hồn phách tiên thạch bên trong.","detail":"Khi đối mặt màn nước ma khí của Hứa Phong Hàn, Vương Lâm lấy đá núi tiên giới ra, khiến nó hóa thành tảng đá lớn. Từ tảng đá này, hắn rút ra hồn phách tiên thạch, biến thành sương mù tiên khí để xuyên phá màn nước.","nguon":["@c0696"]},{"id":"hon-phach-tien-thach","name":"Hồn phách tiên thạch","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm/năng lượng","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"Được rút ra để giao chiến","blurb":"Hồn phách tiên thạch là phần hồn phách được Vương Lâm rút ra từ đá núi tiên giới. Nó hóa thành sương mù mang khí tức tang thương và tiên khí nồng đậm.","detail":"Trong trận đấu với Hứa Phong Hàn, Vương Lâm dùng tay phải nhấc lên, rút hồn phách tiên thạch từ đá núi tiên giới. Hồn phách này hóa thành đám sương tiên khí, xuyên thủng màn nước ma khí rồi được hắn đẩy về phía đối thủ.","nguon":["@c0696"]},{"id":"loi-cau","name":"Lôi cầu","cn":"","category":"khac","categoryLabel":"Vật phẩm lôi lực","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Lôi cầu là khối lôi lực từng bị ma ảnh nuốt nhưng chưa bị hóa giải.","detail":"Trong trận với Hứa Phong Hàn, Vương Lâm dẫn bạo lôi cầu từ bên trong ma ảnh, khiến lôi uy bộc phát và phá nát thân thể ma ảnh màu đen.","nguon":["@c0697"]},{"id":"thanh-truong-thuong","name":"Thanh trường thương","cn":"","category":"phap-bao","categoryLabel":"Pháp khí biến hóa","phamCap":"không rõ","soHuu":["Hứa Phong Hàn"],"trangThai":"hong","blurb":"Thanh trường thương là pháp khí do nước mưa và linh tính biến hóa trong trận giao chiến.","detail":"Thanh trường thương bị sương mù do hồn phách tiên thạch hóa thành áp chế. Khi sương mù quay lại tảng đá, trường thương mất linh tính và trở lại thành nước mưa.","nguon":["@c0697"]},{"id":"manh-vo-phap-bao","name":"Mảnh vỡ pháp bảo","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo tàn phiến","phamCap":"có tiên lực","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Mảnh vỡ pháp bảo là các tàn phiến tỏa tiên lực lộ ra dưới bùn đất trong trận chiến.","detail":"Khi đất cát bị chấn động hất tung, các mảnh vỡ pháp bảo gần thông đạo dưới đất lộ ra. Vương Lâm tranh thủ vung tay thu toàn bộ vào túi trữ vật giữa lúc Hứa Phong Hàn còn đang giao chiến.","nguon":["@c0697"]},{"id":"ma-lien","name":"Ma Liên","cn":"","category":"khac","categoryLabel":"Đạo niệm thực thể","phamCap":"không rõ","soHuu":["Hứa Phong Hàn","Vương Lâm"],"trangThai":"tieu-tan","blurb":"Ma Liên là đạo niệm thực thể của Hứa Phong Hàn, đồng thời là không gian cất giữ vật phẩm.","detail":"Ma Liên bị Đạo Hóa Hoàng Tuyền của Vương Lâm luyện hóa nên chưa tiêu tán ngay sau khi Hứa Phong Hàn chết. Bên trong nó có hắc khí ma hồn và bốn viên quang châu chứa vật phẩm; sau khi ma hồn bị nuốt và quang châu bị lấy đi, Ma Liên héo rũ rồi tan mất.","nguon":["@c0699"]},{"id":"manh-vo-phap-bao-dang-binh","name":"Mảnh vỡ pháp bảo dạng bình","cn":"","category":"phap-bao","categoryLabel":"Mảnh pháp bảo","phamCap":"nghi nguyên khí","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Các mảnh vỡ pháp bảo Vương Lâm thu được sau trận với Hứa Phong Hàn, có thể ghép thành hình bình nhưng không đủ mảnh.","detail":"Vương Lâm nhận ra mười mảnh vỡ có tiên lực ba động cổ quái, ghép thử thành hình bình nước nhưng thiếu một phần nên không thể phục nguyên. Hắn suy đoán đây có thể là pháp bảo nguyên khí luyện chế thất bại hoặc đã vỡ nát.","nguon":["@c0699"]},{"id":"hai-dao-tien-loi","name":"Hai đạo tiên lôi","cn":"","category":"khac","categoryLabel":"Lôi lực","phamCap":"tiên lôi","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Hai đạo tiên lôi từng bị Vương Lâm nuốt nhưng chưa luyện hóa.","detail":"Sau trận chiến với Hứa Phong Hàn, Vương Lâm luyện hóa hai đạo tiên lôi trong động phủ trên Lôi Sơn để bổ sung nguyên lực đã hao tổn khi dùng con mắt thứ ba và Trảm La Quyết.","nguon":["@c0699"]},{"id":"quang-chau-trong-ma-lien","name":"Quang châu trong Ma Liên","cn":"","category":"khac","categoryLabel":"Vật chứa","phamCap":"không rõ","soHuu":["Hứa Phong Hàn","Vương Lâm"],"trangThai":"da-mo","blurb":"Những viên quang châu nằm trong không gian Ma Liên, mỗi viên chứa một vật phẩm.","detail":"Trong Ma Liên có bốn viên quang châu; một viên tự vỡ, Vương Lâm kịp lấy hai viên và mở ra dược bình khắc chữ Hứa cùng một lá bùa có ký hiệu mực đỏ.","nguon":["@c0699"]},{"id":"duoc-binh-khac-chu-hua","name":"Dược bình khắc chữ Hứa","cn":"","category":"khac","categoryLabel":"Vật chứa đan dược","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Dược bình lấy từ quang châu trong Ma Liên, trên bình khắc chữ Hứa.","detail":"Dược bình vẫn còn phong sáp chưa mở, bên trong có một viên đan dược tỏa tiên khí nồng đậm. Vì được Hứa Phong Hàn đặt trong đạo niệm, Vương Lâm nhận định vật này không tầm thường.","nguon":["@c0699"]},{"id":"dan-duoc-trong-duoc-binh-ho-hua","name":"Đan dược trong dược bình họ Hứa","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Viên đan dược trong dược bình khắc chữ Hứa, tiên khí rất nồng đậm.","detail":"Khi Vương Lâm mở dược bình, tiên khí từ viên đan dược khiến thể xác và tinh thần thoải mái. Dược hiệu cụ thể chưa lộ, nhưng hắn nhận định tuyệt không tầm thường.","nguon":["@c0699"]},{"id":"la-bua-ky-hieu-muc-do","name":"Lá bùa ký hiệu mực đỏ","cn":"","category":"khac","categoryLabel":"Phù lục","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Lá bùa rơi ra từ quang châu thứ hai trong Ma Liên, trên đó có ký hiệu mực đỏ khó nhận biết.","detail":"Bề ngoài lá bùa giống phù cấp thấp tầm thường, nhưng vì được Hứa Phong Hàn cất trong đạo niệm nên Vương Lâm cho rằng lai lịch và công dụng của nó không đơn giản.","nguon":["@c0699"]},{"id":"lenh-bai-cua-to-phu-dieu-gia","name":"Lệnh bài của tổ phụ Diêu gia","cn":"","category":"khac","categoryLabel":"Tín vật","phamCap":"không rõ","soHuu":["Diêu Không"],"trangThai":"dang-co","blurb":"Tín vật tổ phụ Diêu gia giao cho Diêu Không để tới Lôi Tiên Điện.","detail":"Sau khi tính ra Diêu Tích Huyết ở Lôi Tiên Giới, tổ phụ Diêu gia bảo Diêu Không cầm lệnh bài tới Lôi Tiên Điện để được tìm cách đưa vào Lôi Tiên Giới.","nguon":["@c0699"]},{"id":"hinh-nhan-moc-linh","name":"Hình nhân mộc linh","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Vật dò trận","phamCap":"không rõ","soHuu":["Người đàn ông trung niên"],"trangThai":"da-dung","blurb":"Hình nhân toàn thân bằng mộc linh, trên người khắc ký tự và dấu ấn. Tu sĩ trung niên dùng nó để dò trận rồi tự bạo phá lớp cấm chế che giấu cửa động.","detail":"Vật này được lấy ra khi tu sĩ trung niên phát hiện trận pháp cấm chế khả nghi. Sau khi bước vào trận, hình nhân tự bạo, làm cấm chế tan vỡ và lộ ra cửa động bên dưới, nhưng cũng khiến chủ nhân rơi vào bẫy thật sự.","nguon":["@c0700"]},{"id":"quat-long-cua-nu-tu","name":"Quạt lông của nữ tu","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo công kích","phamCap":"không rõ","soHuu":["Nữ tu mắt phượng"],"trangThai":"hong","blurb":"Pháp bảo dạng quạt lông được nữ tu dùng để phóng lông chim mang sát khí công kích Vương Lâm. Lông chim bị lôi đình của Vương Lâm đánh tan, khiến nữ tu thổ huyết vì phản chấn.","detail":"Nữ tu lấy quạt lông từ túi trữ vật khi quyết định bắt Vương Lâm làm thức ăn cho thú cưng. Đòn công kích bằng lông chim tưởng như sắc bén nhưng không chịu nổi lôi đình từ ngón trỏ Vương Lâm và bị phá hủy ngay trong một lần va chạm.","nguon":["@c0700"]},{"id":"dan-duoc-cua-to-phu-nu-tu","name":"Đan dược của tổ phụ nữ tu","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược cứu thương","phamCap":"không rõ","soHuu":["Tổ phụ Diêu gia","Lý Nguyên"],"trangThai":"da-dung","blurb":"Đan dược từng được tổ phụ của nữ tu ban cho Lý Nguyên. Theo lời nữ tu, nếu không có đan dược này thì Lý Nguyên đã chết vì thương thế từ trăm năm trước.","detail":"Vật này được nhắc lại trong cuộc đối thoại giữa nữ tu và Lý Nguyên, cho thấy gia tộc nữ tu vừa từng cứu mạng vừa nắm mệnh hồn của hắn. Đan dược là một phần nguyên nhân tạo nên ràng buộc giữa Lý Nguyên và gia tộc ấy.","nguon":["@c0700"]},{"id":"thiet-kiem-den-cua-nu-tu-ho-cat","name":"Thiết kiếm đen của nữ tử họ Cát","cn":"","aliases":["Thiết kiếm","Thanh thiết kiếm"],"category":"phap-bao","categoryLabel":"Pháp bảo gia truyền","phamCap":"Không rõ","soHuu":["Cát Hồng"],"trangThai":"dang-co","blurb":"Thanh thiết kiếm đen do Cát Hồng kế thừa từ gia tộc, bề ngoài bình thường nhưng chuyên đối phó lôi đình.","detail":"Cát Hồng dùng máu và ký hiệu kích hoạt thanh thiết kiếm, khiến nó tỏa quầng sáng để chở nàng và Lý Nguyên vượt qua sợi xích lôi quang. Khi Lý Nguyên đứng ở mũi kiếm, Vương Lâm cảm thấy người và kiếm hòa hợp một thể, cho thấy thanh kiếm có liên hệ sâu với Lý Nguyên.","nguon":["@c0701"]},{"id":"ngoc-gian-cam-che-cua-ly-nguyen","name":"Ngọc giản cấm chế của Lý Nguyên","cn":"","category":"khac","categoryLabel":"Ngọc giản","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Ngọc giản chứa phương pháp cấm chế ẩn giấu thân hình mà Lý Nguyên giao cho Vương Lâm.","detail":"Theo yêu cầu của Vương Lâm, Lý Nguyên in phương pháp cấm chế vào ngọc giản rồi giao ra. Nội dung bên trong khiến Vương Lâm thấy khác với tiên cấm thuật hắn quen biết và hiện ra mười tám pho tượng lớn trong tâm thần.","nguon":["@c0701"]},{"id":"ban-do-co-cua-ly-nguyen","name":"Bản đồ cổ của Lý Nguyên","cn":"","category":"khac","categoryLabel":"Bản đồ","phamCap":"Không rõ","soHuu":["Lý Nguyên"],"trangThai":"dang-co","blurb":"Bản đồ cổ ghi vị trí một bí địa có cấm chế trong Lôi Tiên Giới.","detail":"Lý Nguyên nói mình từng có bản đồ cổ ghi lại nơi bí ẩn tồn tại trước khi Lôi Tiên Giới sụp đổ. Hắn đã nghiên cứu lâu và dùng tin tức này để cầu Vương Lâm tha lỗi.","nguon":["@c0701"]},{"id":"quang-cau-hon-phach-cua-nu-tu-ho-cat","name":"Quang cầu hồn phách của nữ tử họ Cát","cn":"","category":"khac","categoryLabel":"Tín vật hồn phách","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Một phần hồn phách của Cát Hồng bị Vương Lâm rút ra và ngưng thành quang cầu làm tín vật.","detail":"Vương Lâm không lấy hồn Lý Nguyên mà chụp lấy hồn ảnh của nữ tử họ Cát, rút một quang cầu từ mi tâm hồn ảnh rồi cất vào túi trữ vật để khống chế chuyến đi.","nguon":["@c0701"]},{"id":"thiet-kiem","name":"Thiết kiếm","cn":"","aliases":["Thiết kiếm của Lý Nguyên"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Lý Nguyên"],"trangThai":"dang-co","blurb":"Thanh thiết kiếm chở Lý Nguyên và Cát Hồng đi trong hư vô Lôi Tiên Giới. Nó có quầng sáng chống lôi quang rất mạnh nhưng bị ảnh hưởng khi sợi xích lôi đình chấn động dữ dội.","detail":"Trong hành trình gần hai tháng, thiết kiếm là vật để Lý Nguyên đứng ở mũi kiếm và chở Cát Hồng đi qua hư vô đầy lôi quang. Vương Lâm quan sát nhiều lần, nhận ra lôi quang càng đậm nhưng thanh kiếm vẫn không suy chuyển; về sau khi sợi xích lôi đình chấn động mạnh, quầng sáng quanh kiếm bắt đầu tan rã.","nguon":["@c0702"]},{"id":"la-ban","name":"La bàn","cn":"","aliases":["La bàn của Lý Nguyên"],"category":"khac","categoryLabel":"Vật phẩm cấm chế","phamCap":"không rõ","soHuu":["Lý Nguyên"],"trangThai":"hong","blurb":"Vật phẩm Lý Nguyên dùng để tính toán cấm chế trước đám sương mù chắn đường. Kim đồng hồ trên la bàn xoay loạn rồi la bàn nổ tung thành tro bụi.","detail":"Khi phát hiện đám sương mù tiên khí phía trước là cấm chế, Lý Nguyên lấy la bàn ra để tính toán. Kim đồng hồ run rẩy xoay liên tục, sau đó vật này nổ tan, giúp làm nổi bật mức độ nguy hiểm và phức tạp của cấm chế thiên cấp trung phẩm.","nguon":["@c0702"]},{"id":"soi-xich-loi-quang","name":"Sợi xích lôi quang","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật lôi đình","phamCap":"không rõ","soHuu":[],"trangThai":"dang-ton-tai","blurb":"Đường nối lôi đình giữa các mảnh vỡ trong Lôi Tiên Giới. Chương này nhiều sợi xích lôi quang chấn động bất thường, báo hiệu nguy cơ sụp đổ mảnh vỡ đại lục.","detail":"Sợi xích lôi quang nối giữa các mảnh vỡ đại lục trong Lôi Tiên Giới vốn theo lời lão tổ nhà Lý Nguyên là chưa từng lay động. Khi nhóm Vương Lâm đi sâu vào hư vô, chấn động truyền tới khiến Vương Lâm suy yếu và khiến Lý Nguyên nhận ra nguy cơ hai mảnh vỡ đại lục có thể sụp đổ; cuối chương, lão già bí ẩn còn cầm một sợi xích lôi quang bước ra từ sương mù cấm chế.","nguon":["@c0702"]},{"id":"loi-quang-thiet-lien","name":"Lôi quang thiết liên","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ, có chứa chút Tiên lôi","soHuu":["Lão già chủ Lôi tiên giới cầm Lôi quang thiết liên"],"trangThai":"đang được lão già nắm giữ","blurb":"Sợi xích sắt tỏa lôi quang trong tay lão già Lôi tiên giới, ẩn chứa một chút Tiên lôi. Vương Lâm dù có nguyên thần thuộc tính lôi và lôi thể cũng không thể cầm nó thoải mái như lão.","detail":"Lôi quang thiết liên là sợi xích sắt do lão già cầm khi xuất hiện trước nhóm Vương Lâm. Chớp trên xích ẩn chứa Tiên lôi, khiến Vương Lâm nhận ra bản thân dù có lôi nguyên thần và lôi thể vẫn không đủ khả năng nắm giữ như lão; lão còn muốn dùng Lôi thú sừng bạc để kéo thiết liên.","nguon":["@c0703"]},{"id":"qua-cau-sang-ngung-tu-tu-hat-bui","name":"Quả cầu sáng ngưng tụ từ hạt bụi","cn":"","category":"khac","categoryLabel":"Vật phẩm hoặc thủ đoạn","phamCap":"Không rõ","soHuu":["Lão già chủ Lôi tiên giới cầm Lôi quang thiết liên"],"trangThai":"đã chui vào ngực Vương Lâm","blurb":"Quả cầu sáng do lão già ngưng tụ từ vô số hạt bụi rồi thổi vào ngực Vương Lâm. Lão nói đây là cách giúp Vương Lâm tu luyện lôi nguyên thần và lôi thể.","detail":"Sau khi chê Vương Lâm tu luyện lôi nguyên thần và lôi thể như trẻ con chơi đùa, lão già giơ tay chộp không trung, ngưng tụ vô số hạt bụi thành một quả cầu sáng. Lão thổi nhẹ khiến quả cầu bắn thẳng vào ngực Vương Lâm, nhanh đến mức hắn không kịp né tránh.","nguon":["@c0703"]},{"id":"chuy-thu-mau-den","name":"Chủy thủ màu đen","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo truyền thừa","phamCap":"không rõ","soHuu":["Cát Hồng","Vương Lâm"],"trangThai":"Vương Lâm thu giữ","blurb":"Chủy thủ truyền thừa của gia tộc Cát Hồng, chứa kịch độc ăn mòn thân thể và âm hồn gây thương tổn nguyên thần.","detail":"Cát Hồng lấy chủy thủ này ra từ túi trữ vật để nhân lúc Vương Lâm đau đớn mà ám toán. Khi bị Vương Lâm mở mắt uy hiếp ngược, nàng hoảng sợ ném chủy thủ xuống đất, để hắn chộp lấy và cất vào túi trữ vật.","nguon":["@c0704"]},{"id":"kiem-khi-cua-lang-thien-hau","name":"Kiếm khí của Lăng Thiên Hậu","cn":"","aliases":[],"category":"khac","categoryLabel":"Kiếm khí","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đã sử dụng để uy hiếp Lý Nguyên","blurb":"Đạo kiếm khí do Lăng Thiên Hậu lưu lại trong tay Vương Lâm, được phóng ra tại ngọn núi vô danh. Nó dừng trước mi tâm Lý Nguyên như một thanh bảo kiếm, buộc Lý Nguyên phải nhìn nhận lại thế yếu.","detail":"Sau khi dùng Tiên Vệ khôi lỗi chứng minh ngọn núi không thể khóa mình, Vương Lâm tiếp tục phóng kiếm khí của Lăng Thiên Hậu. Đạo kiếm khí này cực nhanh, áp sát mi tâm Lý Nguyên và trở thành đòn uy hiếp trực tiếp trong cuộc mặc cả về thù lao.","nguon":["@c0705"]},{"id":"phap-bao-truyen-thua-cua-cat-gia","name":"Pháp bảo truyền thừa của Cát gia","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo gia tộc","phamCap":"không rõ","soHuu":["Cát Hồng"],"trangThai":"đang ở trong tay Cát Hồng","blurb":"Pháp bảo gia tộc do lão tổ Cát gia truyền cho Cát Hồng trước khi nàng vào Lôi tiên giới. Trong suy nghĩ của Cát Hồng, việc nhận pháp bảo này gắn với chuộc tội và hiến tế hồn phách.","detail":"Khi nhận ra bí mật giữa Cát gia, Lý Nguyên và ngọn núi vô danh, Cát Hồng hồi tưởng việc lão tổ truyền pháp bảo gia tộc cho mình. Nàng hiểu rằng sự sắp đặt ấy không đơn thuần là bảo hộ, mà liên quan đến việc gia tộc từng có người vào Lôi tiên giới rồi không trở về.","nguon":["@c0705"]},{"id":"ngoc-gian-mai-hoa-thap-tam-cam","name":"Ngọc giản Mai hoa thập tam cấm","cn":"","aliases":[],"category":"khac","categoryLabel":"Ngọc giản","phamCap":"không rõ","soHuu":["Lý Nguyên","Vương Lâm"],"trangThai":"Vương Lâm đang giữ","blurb":"Ngọc giản Mai hoa thập tam cấm là vật Lý Nguyên giao trước cho Vương Lâm khi tới ngọn núi cấm thuật. Bên trong ghi mười ba hình ảnh lớn và mười ba đóa hoa mai.","detail":"Lý Nguyên lấy ngọc giản từ túi trữ vật, giao cho Vương Lâm để đáp ứng yêu cầu về Mai Hoa thuật. Ngọc giản chứa Mai hoa thập tam cấm, còn các phần khác được Lý Nguyên hẹn giao sau khi vào núi.","nguon":["@c0706"]},{"id":"hoa-truc","name":"Họa trục","cn":"","aliases":["Bức họa","Họa trục của Lý Nguyên"],"category":"khac","categoryLabel":"Vật phẩm","phamCap":"không rõ","soHuu":["Lý Nguyên"],"trangThai":"Lý Nguyên đang giữ","blurb":"Họa trục là một trong ba vật Cát Hồng giao cho Lý Nguyên để cầu sống. Bức họa vẽ ngọn núi, phi kiếm, người trên chuôi kiếm và bóng người trên mũi kiếm giống Lý Nguyên.","detail":"Sau khi nhận túi trữ vật từ Cát Hồng, Lý Nguyên lấy ra họa trục và tỏ ra đặc biệt trân trọng. Hình ảnh trong họa trục hé lộ mối liên hệ giữa ngọn núi, thanh phi kiếm, chủ nhân trên chuôi kiếm và người đứng trên mũi kiếm.","nguon":["@c0706"]},{"id":"thanh-phi-kiem","name":"Thanh phi kiếm","cn":"","aliases":["Bảo kiếm trong huyễn cảnh","Thanh bảo kiếm tím"],"category":"phap-bao","categoryLabel":"Kiếm","phamCap":"không rõ","soHuu":["Chủ nhân của Lý Nguyên"],"trangThai":"xuất hiện trong họa trục, tượng đá và huyễn cảnh","blurb":"Thanh phi kiếm xuất hiện xuyên suốt qua họa trục, tượng đá và huyễn cảnh. Trong huyễn cảnh, nó là bảo kiếm được vô số tia chớp tím bao quanh, chở chủ nhân trên chuôi kiếm và người hầu trên mũi kiếm.","detail":"Bức họa cho thấy một thanh phi kiếm gắn với ngọn núi, nam tử trên chuôi kiếm và người trên mũi kiếm. Khi Vương Lâm rơi vào huyễn cảnh, thanh kiếm hiện ra giữa lôi điện tím, trở thành trung tâm của cảnh chủ nhân tan rã và người hầu lao theo.","nguon":["@c0706"]}]};
